def date_digit_sum(date_input, date_format='DMY', delimiter=' ', calendar_system='Gregorian', output_mode='total'):
    """
    Calculate the sum of all digits in the day, month, and year of a given date.

    Parameters:
    - date_input (str): The date string to be processed.
    - date_format (str): The format of the input date. Defaults to 'DMY'.
    - delimiter (str): The delimiter used in the date string. Defaults to space.
    - calendar_system (str): The calendar system used for the date. Defaults to 'Gregorian'.
    - output_mode (str): The mode of output. Defaults to 'total'.

    Returns:
    - int or dict: The sum of all digits or a dictionary with separate sums.
    """
    # Error handling for unsupported calendar systems
    if calendar_system not in ['Gregorian', 'Julian', 'Islamic', 'Hebrew']:
        return {'error': 'Unsupported calendar system'}

    # Error handling for unsupported date formats
    if date_format not in ['DMY', 'MDY', 'YMD', 'YDM']:
        return {'error': 'Unsupported date format'}

    # Split the date input based on the delimiter
    try:
        date_parts = date_input.split(delimiter)
    except Exception as e:
        return {'error': f'Invalid delimiter or date input: {str(e)}'}

    # Map the date parts to day, month, year based on the format
    try:
        if date_format == 'DMY':
            day, month, year = date_parts
        elif date_format == 'MDY':
            month, day, year = date_parts
        elif date_format == 'YMD':
            year, month, day = date_parts
        elif date_format == 'YDM':
            year, day, month = date_parts
    except ValueError:
        return {'error': 'Date input does not match the specified format'}

    # Function to calculate digit sum
    def digit_sum(s):
        return sum(int(char) for char in s if char.isdigit())

    # Calculate digit sums
    day_sum = digit_sum(day)
    month_sum = digit_sum(month)
    year_sum = digit_sum(year)

    if output_mode == 'total':
        return day_sum + month_sum + year_sum
    elif output_mode == 'component':
        return {'day_sum': day_sum, 'month_sum': month_sum, 'year_sum': year_sum}
    else:
        return {'error': 'Invalid output mode'}

