def digit_extractor_v2(number, position, direction='left', output_format='integer', error_handling='raise'):
    # Convert the number to a string to facilitate digit extraction
    num_str = str(abs(int(number)))

    # Determine the length of the number
    num_length = len(num_str)

    # Adjust position based on direction
    if direction == 'right':
        position = num_length - position + 1

    # Check if position is valid
    if position < 1 or position > num_length:
        if error_handling == 'raise':
            raise ValueError('Position out of range')
        elif error_handling == 'warn':
            print('Warning: Position out of range')
            return None
        elif error_handling == 'ignore':
            return None

    # Extract the digit
    digit = num_str[position - 1]

    # Format the output
    if output_format == 'integer':
        return int(digit)
    elif output_format == 'string':
        return digit
    elif output_format == 'json':
        return {'digit': digit}

