def extract_digit(number: str, position: int, output_format: str = 'integer', numeral_system: str = 'decimal', count_direction: str = 'left'):
    # Validate numeral system
    if numeral_system not in ['decimal', 'binary', 'hexadecimal']:
        return {'error': 'Invalid numeral system'}

    # Validate count direction
    if count_direction not in ['left', 'right']:
        return {'error': 'Invalid count direction'}

    # Convert number to the appropriate numeral system
    if numeral_system == 'binary':
        try:
            number = bin(int(number, 2))[2:]
        except ValueError:
            return {'error': 'Invalid binary number'}
    elif numeral_system == 'hexadecimal':
        try:
            number = hex(int(number, 16))[2:]
        except ValueError:
            return {'error': 'Invalid hexadecimal number'}

    # Adjust position based on count direction
    if count_direction == 'right':
        position = len(number) - position + 1

    # Check if position is valid
    if position < 1 or position > len(number):
        return {'error': 'Position out of range'}

    # Extract the digit
    digit = number[position - 1]

    # Return the digit in the requested format
    if output_format == 'integer':
        return int(digit)
    elif output_format == 'string':
        return digit
    else:
        return {'error': 'Invalid output format'}

