def last_letter_extractor_v2(names, output_format='list', case_sensitive=True, error_handling='warn'):
    # Validate input parameters
    if not isinstance(names, list) or not all(isinstance(name, str) and name for name in names):
        if error_handling == 'strict':
            raise ValueError('All names must be non-empty strings.')
        elif error_handling == 'warn':
            print('Warning: All names should be non-empty strings.')
        if error_handling == 'ignore':
            names = [name for name in names if isinstance(name, str) and name]

    # Extract last letters
    last_letters = [name[-1] for name in names]

    # Format output
    if output_format == 'character' and len(last_letters) == 1:
        return last_letters[0]
    elif output_format == 'list':
        return last_letters
    elif output_format == 'json':
        return {name: last_letter for name, last_letter in zip(names, last_letters)}
    else:
        raise ValueError('Invalid output format specified.')

