def enhanced_last_letter_extractor(input, ignore_non_alpha=True, output_format='array', character_set='latin', error_handling='warn'):
    # Validate input
    if not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        if error_handling == 'strict':
            raise ValueError('Input must be a list of strings.')
        elif error_handling == 'warn':
            print('Warning: Input must be a list of strings.')
        return []

    # Define character sets
    char_sets = {
        'latin': 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ',
        'cyrillic': 'абвгдежзийклмнопрстуфхцчшщъыьэюяАБВГДЕЖЗИЙКЛМНОПРСТУФХЦЧШЩЪЫЬЭЮЯ',
        'greek': 'αβγδεζηθικλμνξοπρστυφχψωΑΒΓΔΕΖΗΘΙΚΛΜΝΞΟΠΡΣΤΥΦΧΨΩ',
        'all': None  # Consider all characters
    }

    # Function to extract last letter
    def get_last_letter(s):
        if ignore_non_alpha:
            s = ''.join(filter(str.isalpha, s))
        if not s:
            return ''
        if character_set != 'all':
            s = ''.join(filter(lambda x: x in char_sets[character_set], s))
        return s[-1] if s else ''

    # Extract last letters
    last_letters = [get_last_letter(s) for s in input]

    # Handle output format
    if output_format == 'string':
        return ''.join(last_letters)
    elif output_format == 'array':
        return last_letters
    elif output_format == 'json':
        return {s: get_last_letter(s) for s in input}

    # Default return
    return last_letters

# Example usage
result = enhanced_last_letter_extractor(['Saint-Cyr'])
print(result)  # Output: ['r']

def string_concatenator(strings, separator='', output_format='plain', prefix='', suffix='', case_transformation='none'):
    # Error handling for required parameters
    if not isinstance(strings, list) or len(strings) < 2:
        return {'error': 'Invalid input: At least two strings are required.'}
    if not all(isinstance(s, str) for s in strings):
        return {'error': 'Invalid input: All items in strings must be of type string.'}

    # Concatenate strings with separator
    result = separator.join(strings)

    # Apply prefix and suffix
    result = f'{prefix}{result}{suffix}'

    # Case transformation
    if case_transformation == 'uppercase':
        result = result.upper()
    elif case_transformation == 'lowercase':
        result = result.lower()
    elif case_transformation == 'capitalize':
        result = result.capitalize()

    # Output formatting
    if output_format == 'json':
        import json
        result = json.dumps({'result': result})
    elif output_format == 'html':
        result = f'<p>{result}</p>'
    elif output_format == 'xml':
        result = f'<result>{result}</result>'

    return result

