def chemist_identifier(query: str, nationality: str = None, contribution: str = None, era: str = None, field_of_study: str = None, output_format: str = 'name_only', include_awards: bool = False):
    """
    Identifies a chemist based on the provided query and optional parameters.
    """
    # Error handling for required parameter
    if not query:
        return {'error': 'The query parameter is required.'}

    # Simulated database of chemists
    chemists_db = [
        {'name': 'S. P. L. Sørensen', 'nationality': 'Danish', 'contribution': 'pH', 'era': '20th century', 'field_of_study': 'biochemistry', 'awards': ['Nobel Prize']},
        # Additional chemist entries can be added here
    ]

    # Search logic
    results = []
    for chemist in chemists_db:
        if query.lower() in chemist['contribution'].lower():
            if nationality and nationality.lower() != chemist['nationality'].lower():
                continue
            if contribution and contribution.lower() not in chemist['contribution'].lower():
                continue
            if era and era.lower() != chemist['era'].lower():
                continue
            if field_of_study and field_of_study.lower() != chemist['field_of_study'].lower():
                continue
            results.append(chemist)

    # Format the output based on 'output_format'
    if not results:
        return {'error': 'No chemist found matching the criteria.'}

    chemist = results[0]  # Assuming we return the first match
    if output_format == 'name_only':
        return {'name': chemist['name']}
    elif output_format == 'detailed':
        return {
            'name': chemist['name'],
            'nationality': chemist['nationality'],
            'contribution': chemist['contribution'],
            'era': chemist['era'],
            'field_of_study': chemist['field_of_study'],
            'awards': chemist['awards'] if include_awards else None
        }
    elif output_format == 'summary':
        return {
            'summary': f"{chemist['name']} is a {chemist['nationality']} chemist known for {chemist['contribution']} in the {chemist['era']}."
        }
    else:
        return {'error': 'Invalid output format specified.'}

# Example usage
result = chemist_identifier(query='pH', nationality='Danish', output_format='name_only')
print(result)  # Expected output: {'name': 'S. P. L. Sørensen'}

