def enhanced_palindrome_finder(input_number, range_limit=100, output_format='closest', search_direction='both', include_distance=False):
    # Helper function to check if a number is a palindrome
    def is_palindrome(num):
        return str(num) == str(num)[::-1]

    # Initialize variables
    closest_palindrome = None
    min_distance = float('inf')

    # Search for the closest palindrome
    if search_direction in ['both', 'lower']:
        for num in range(input_number, input_number - range_limit - 1, -1):
            if is_palindrome(num):
                distance = abs(input_number - num)
                if distance < min_distance:
                    closest_palindrome = num
                    min_distance = distance
                if output_format == 'closest':
                    break

    if search_direction in ['both', 'higher']:
        for num in range(input_number, input_number + range_limit + 1):
            if is_palindrome(num):
                distance = abs(input_number - num)
                if distance < min_distance:
                    closest_palindrome = num
                    min_distance = distance
                if output_format == 'closest':
                    break

    # Prepare the result based on the output format
    if output_format == 'closest':
        result = closest_palindrome
        if include_distance:
            result = (closest_palindrome, min_distance)
    elif output_format == 'list':
        result = [num for num in range(input_number - range_limit, input_number + range_limit + 1) if is_palindrome(num)]
    elif output_format == 'detailed':
        result = [{'number': num, 'distance': abs(input_number - num)} for num in range(input_number - range_limit, input_number + range_limit + 1) if is_palindrome(num)]
    else:
        raise ValueError("Invalid output_format specified.")

    return result

