def count_characters(input, ignore_characters=None, ignore_position=None, case_sensitive=False, character_types=None, output_format='integer'):
    # Validate input types
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if ignore_characters and not all(isinstance(ch, str) for ch in ignore_characters):
        return {'error': 'All ignore_characters must be strings.'}
    if ignore_position and not all(pos in ['first', 'last', 'even', 'odd'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position value.'}
    if character_types and not all(ct in ['alphabets', 'digits', 'special'] for ct in character_types):
        return {'error': 'Invalid character_types value.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format value.'}

    # Initialize character count
    count = 0
    detailed_count = {'alphabets': 0, 'digits': 0, 'special': 0}

    # Define character type checks
    def is_alphabet(ch):
        return ch.isalpha()

    def is_digit(ch):
        return ch.isdigit()

    def is_special(ch):
        return not ch.isalnum()

    # Process input string
    for i, ch in enumerate(input):
        # Apply ignore_position logic
        if ignore_position:
            if ('first' in ignore_position and i == 0) or \
               ('last' in ignore_position and i == len(input) - 1) or \
               ('even' in ignore_position and i % 2 == 0) or \
               ('odd' in ignore_position and i % 2 != 0):
                continue

        # Apply ignore_characters logic
        if ignore_characters and ch in ignore_characters:
            continue

        # Apply case sensitivity
        if not case_sensitive:
            ch = ch.lower()

        # Count based on character_types
        if character_types:
            if 'alphabets' in character_types and is_alphabet(ch):
                count += 1
                detailed_count['alphabets'] += 1
            elif 'digits' in character_types and is_digit(ch):
                count += 1
                detailed_count['digits'] += 1
            elif 'special' in character_types and is_special(ch):
                count += 1
                detailed_count['special'] += 1
        else:
            # Default to counting all character types
            count += 1
            if is_alphabet(ch):
                detailed_count['alphabets'] += 1
            elif is_digit(ch):
                detailed_count['digits'] += 1
            elif is_special(ch):
                detailed_count['special'] += 1

    # Return output in the specified format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'Total characters counted: {count}'
    elif output_format == 'detailed':
        return detailed_count

