def longest_alphabetical_substring(input_string, case_sensitive=False, min_length=1, exclude_non_alpha=False):
    # Validate input types
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'case_sensitive must be a boolean'}
    if not isinstance(min_length, int) or min_length < 1:
        return {'error': 'min_length must be a positive integer'}
    if not isinstance(exclude_non_alpha, bool):
        return {'error': 'exclude_non_alpha must be a boolean'}

    # Prepare the input string based on parameters
    if not case_sensitive:
        input_string = input_string.lower()
    if exclude_non_alpha:
        input_string = ''.join(filter(str.isalpha, input_string))

    # Initialize variables to track the longest substring
    longest = ''
    current = ''

    # Iterate through the string to find the longest alphabetical substring
    for i in range(len(input_string)):
        if i == 0 or input_string[i] >= input_string[i - 1]:
            current += input_string[i]
        else:
            if len(current) >= min_length and len(current) > len(longest):
                longest = current
            current = input_string[i]

    # Final check for the last substring
    if len(current) >= min_length and len(current) > len(longest):
        longest = current

    return longest if longest else {'error': 'No valid substring found'}

