        return {'error': 'Invalid ignore_characters type. Must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last', 'even', 'odd', 'custom'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position type. Must be a list with valid position strings.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive type. Must be a boolean.'}
    if not isinstance(count_types, list) or not all(ct in ['all', 'vowels', 'consonants', 'digits', 'special'] for ct in count_types):
        return {'error': 'Invalid count_types type. Must be a list with valid character type strings.'}
    if not isinstance(multi_character_sequences, list) or not all(isinstance(seq, str) for seq in multi_character_sequences):
        return {'error': 'Invalid multi_character_sequences type. Must be a list of strings.'}

    # Convert input to lowercase if case_sensitive is False
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [ch.lower() for ch in ignore_characters]
        multi_character_sequences = [seq.lower() for seq in multi_character_sequences]

    # Remove multi-character sequences
    for seq in multi_character_sequences:
        input = input.replace(seq, '')

    # Remove ignored characters
    input = ''.join(ch for ch in input if ch not in ignore_characters)

    # Remove characters based on ignore_position
    if 'first' in ignore_position and len(input) > 0:
        input = input[1:]
    if 'last' in ignore_position and len(input) > 0:
        input = input[:-1]
    if 'even' in ignore_position:
        input = ''.join(ch for i, ch in enumerate(input) if i % 2 != 0)
    if 'odd' in ignore_position:
        input = ''.join(ch for i, ch in enumerate(input) if i % 2 == 0)

    # Count characters based on count_types
    count = 0
    for ch in input:
        if 'all' in count_types:
            count += 1
        elif 'vowels' in count_types and ch in 'aeiou':
            count += 1
        elif 'consonants' in count_types and ch.isalpha() and ch not in 'aeiou':
            count += 1
        elif 'digits' in count_types and ch.isdigit():
            count += 1
        elif 'special' in count_types and not ch.isalnum():
