def letter_counter_plus(input, letters, case_sensitive=False, language_support='en', detailed_statistics=False):
    # Error handling for required parameters
    if not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        return {'error': 'Invalid input: input must be a list of strings.'}
    if not isinstance(letters, list) or not all(isinstance(l, str) and len(l) == 1 for l in letters):
        return {'error': 'Invalid letters: letters must be a list of single-character strings.'}

    # Initialize result dictionary
    result = {letter: 0 for letter in letters}

    # Process each string in the input
    for string in input:
        # Adjust case sensitivity
        if not case_sensitive:
            string = string.lower()
            letters = [letter.lower() for letter in letters]

        # Count occurrences of each letter
        for letter in letters:
            result[letter] += string.count(letter)

    # Provide detailed statistics if required
    if detailed_statistics:
        detailed_result = {letter: {'count': result[letter], 'percentage': (result[letter] / sum(result.values())) * 100} for letter in letters}
        return {'detailed_statistics': detailed_result}

    return {'counts': result}

