def name_length_counter(name, ignore_characters=None, ignore_position=None, ignore_patterns=None, output_format='integer'):
    # Validate input types
    if not isinstance(name, str):
        return {'error': 'Invalid input: name must be a string.'}
    if ignore_characters and not all(isinstance(c, str) for c in ignore_characters):
        return {'error': 'Invalid input: ignore_characters must be a list of strings.'}
    if ignore_position and not all(p in ['first', 'last', 'even', 'odd'] for p in ignore_position):
        return {'error': 'Invalid input: ignore_position must be a list containing only "first", "last", "even", or "odd".'}
    if ignore_patterns and not all(isinstance(p, str) for p in ignore_patterns):
        return {'error': 'Invalid input: ignore_patterns must be a list of strings.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid input: output_format must be "integer", "text", or "detailed".'}

    # Initialize variables
    count = 0
    detailed_count = {}

    # Process the name
    for i, char in enumerate(name):
        # Check ignore conditions
        if ignore_characters and char in ignore_characters:
            continue
        if ignore_position:
            if 'first' in ignore_position and i == 0:
                continue
            if 'last' in ignore_position and i == len(name) - 1:
                continue
            if 'even' in ignore_position and i % 2 == 0:
                continue
            if 'odd' in ignore_position and i % 2 != 0:
                continue
        if ignore_patterns and any(pattern in name[i:] for pattern in ignore_patterns):
            continue

        # Count the character
        count += 1
        if output_format == 'detailed':
            if char in detailed_count:
                detailed_count[char] += 1
            else:
                detailed_count[char] = 1

    # Return result based on output_format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The name "{name}" has {count} letters.'
    elif output_format == 'detailed':
        return detailed_count

