def extract_first_letter_v2(input, case_sensitive=True, output_format='character', error_handling='warn', default_value=''):
    """
    Extracts the first letter from the input based on the specified parameters.

    Parameters:
    - input (str or list): The input from which the first letter will be extracted.
    - case_sensitive (bool): Maintains the original case if True. Defaults to True.
    - output_format (str): The format of the output ('character', 'ascii', 'unicode'). Defaults to 'character'.
    - error_handling (str): Behavior for non-string inputs ('ignore', 'warn', 'strict'). Defaults to 'warn'.
    - default_value (str): Default value if input is empty or invalid. Defaults to an empty string.

    Returns:
    - str or int: The first letter in the specified format, or the default value.
    """
    if isinstance(input, str):
        first_letter = input[0] if input else default_value
    elif isinstance(input, list) and input:
        first_letter = input[0][0] if input[0] else default_value
    else:
        if error_handling == 'strict':
            raise ValueError("Invalid input type. Expected a string or a list of strings.")
        elif error_handling == 'warn':
            print("Warning: Invalid input type. Returning default value.")
        return default_value

    if not case_sensitive:
        first_letter = first_letter.lower()

    if output_format == 'ascii':
        return ord(first_letter)
    elif output_format == 'unicode':
        return f'U+{ord(first_letter):04X}'
    else:
        return first_letter

