def extract_last_name(full_name, name_format='first_last', handle_special_characters=True, output_format='string', case_sensitivity=False, ignore_titles=True):
    """
    Extracts the last name from a full name string based on specified parameters.

    :param full_name: The full name from which the last name is to be extracted.
    :param name_format: The expected format of the name. Defaults to 'first_last'.
    :param handle_special_characters: Indicates whether to handle special characters in names. Defaults to true.
    :param output_format: The format of the output. Defaults to 'string'.
    :param case_sensitivity: Indicates whether the extraction should be case-sensitive. Defaults to false.
    :param ignore_titles: Indicates whether to ignore titles in the name. Defaults to true.
    :return: Extracted last name or detailed information based on output_format.
    """
    # Error handling for required parameter
    if not full_name:
        return {'error': 'The full_name parameter is required.'}

    # Split the full name into parts
    name_parts = full_name.split()

    # Handle title ignoring
    if ignore_titles:
        titles = {'Dr.', 'Mr.', 'Ms.', 'Mrs.', 'Miss', 'Mx.'}
        name_parts = [part for part in name_parts if part not in titles]

    # Determine the last name based on the name format
    last_name = ''
    if name_format == 'first_last':
        last_name = name_parts[-1] if len(name_parts) > 1 else name_parts[0]
    elif name_format == 'first_middle_last':
        last_name = name_parts[-1] if len(name_parts) > 2 else name_parts[-1]
    elif name_format == 'single_name':
        last_name = name_parts[0]
    elif name_format == 'compound_last':
        last_name = ' '.join(name_parts[1:]) if len(name_parts) > 1 else name_parts[0]
    elif name_format == 'hyphenated_last':
        last_name = name_parts[-1] if '-' in name_parts[-1] else name_parts[-1]
    else:
        return {'error': 'Unsupported name format.'}

    # Handle case sensitivity
    if not case_sensitivity:
        last_name = last_name.lower().capitalize()

    # Handle special characters
    if handle_special_characters:
        import re
        last_name = re.sub(r'[^a-zA-Z\-\s]', '', last_name)

    # Return based on output format
    if output_format == 'string':
        return last_name
    elif output_format == 'json':
        return {'last_name': last_name}
    elif output_format == 'detailed_json':
        return {
            'last_name': last_name,
            'full_name': full_name,
            'name_format': name_format,
            'case_sensitivity': case_sensitivity,
            'ignore_titles': ignore_titles
        }
    else:
        return {'error': 'Unsupported output format.'}

