def character_counter(input, target_characters=['a', 'e', 'i', 'o', 'u'], ignore_characters=None, ignore_position=None, output_format='integer', case_sensitive=False, frequency_analysis=False):
    # Validate input
    if not isinstance(input, list) or len(input) < 1 or len(input) > 10:
        return {'error': 'Input must be a list of 1 to 10 strings.'}
    if not all(isinstance(s, str) for s in input):
        return {'error': 'All items in input must be strings.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output format.'}

    # Prepare target characters
    if not case_sensitive:
        target_characters = [char.lower() for char in target_characters]

    # Initialize count
    total_count = 0
    detailed_count = {char: 0 for char in target_characters}

    # Count characters
    for string in input:
        if not case_sensitive:
            string = string.lower()
        for i, char in enumerate(string):
            if ignore_characters and char in ignore_characters:
                continue
            if ignore_position:
                if 'first' in ignore_position and i == 0:
                    continue
                if 'last' in ignore_position and i == len(string) - 1:
                    continue
            if char in target_characters:
                total_count += 1
                detailed_count[char] += 1

    # Prepare output
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total count of target characters: {total_count}'
    elif output_format == 'detailed':
        return {'total': total_count, 'detailed': detailed_count}

    # Frequency analysis
    if frequency_analysis:
        frequency = {char: count / total_count for char, count in detailed_count.items() if total_count > 0}
        return {'total': total_count, 'detailed': detailed_count, 'frequency': frequency}

    return total_count

