def arithmetic_calculator(operation, operands, output_format='number', precision=2, error_handling='strict'):
    # Validate operation
    if operation not in ['add', 'subtract', 'multiply', 'divide', 'exponentiate', 'modulus']:
        if error_handling == 'strict':
            raise ValueError('Invalid operation specified.')
        elif error_handling == 'warn':
            print('Warning: Invalid operation specified.')
            return None
        else:
            return None

    # Validate operands
    if len(operands) < 2:
        if error_handling == 'strict':
            raise ValueError('At least two operands are required.')
        elif error_handling == 'warn':
            print('Warning: At least two operands are required.')
            return None
        else:
            return None

    # Perform the operation
    try:
        if operation == 'add':
            result = sum(operands)
        elif operation == 'subtract':
            result = operands[0] - sum(operands[1:])
        elif operation == 'multiply':
            result = 1
            for num in operands:
                result *= num
        elif operation == 'divide':
            result = operands[0]
            for num in operands[1:]:
                result /= num
        elif operation == 'exponentiate':
            result = operands[0] ** operands[1]
        elif operation == 'modulus':
            result = operands[0] % operands[1]
    except ZeroDivisionError:
        if error_handling == 'strict':
            raise ZeroDivisionError('Division by zero encountered.')
        elif error_handling == 'warn':
            print('Warning: Division by zero encountered.')
            return None
        else:
            return None

    # Format the result
    if output_format == 'text':
        result = f'{result:.{precision}f}'
    else:
        result = round(result, precision)

    return result

