print(result)  # Output: 9098

def next_year_calculator_v2(years, output_format='integer', error_handling='strict'):
    """
    Calculate the year following each year in the input list.

    Parameters:
    - years (list of int): A list of base years from which to calculate the next year.
    - output_format (str): The format of the output ('integer', 'string', 'json').
    - error_handling (str): How to handle invalid inputs ('ignore', 'warn', 'strict').

    Returns:
    - The next year(s) in the specified format.
    """
    results = []
    warnings = []

    for year in years:
        if not isinstance(year, int):
            if error_handling == 'strict':
                raise ValueError(f"Invalid year: {year}. Year must be an integer.")
            elif error_handling == 'warn':
                warnings.append(f"Warning: Invalid year {year} skipped.")
                continue
            elif error_handling == 'ignore':
                continue

        next_year = year + 1
        if output_format == 'integer':
            results.append(next_year)
        elif output_format == 'string':
            results.append(str(next_year))
        elif output_format == 'json':
            results.append({"year": next_year})

    if error_handling == 'warn' and warnings:
        for warning in warnings:
            print(warning)

    if output_format == 'json':
        return {"next_years": results}
    return results

