    # Validate 'names' parameter
    if not isinstance(names, list) or not all(isinstance(name, str) for name in names):
        raise ValueError("'names' must be a list of strings.")
    if len(names) < 1:
        raise ValueError("'names' must contain at least one name.")

    # Validate 'output_format'
    if output_format not in ['array', 'string']:
        raise ValueError("'output_format' must be either 'array' or 'string'.")

    # Extract first letters
    first_letters = []
    for name in names:
        first_letter = default_character
        for char in name:
            if ignore_non_alpha and not char.isalpha():
                continue
            first_letter = char
            break
        if not case_sensitive:
            first_letter = first_letter.lower()
        first_letters.append(f'{prefix}{first_letter}{suffix}')

    # Return result in specified format
    if output_format == 'string':
        return ''.join(first_letters)
    return first_letters

