def letter_counter(input_string, letters, case_sensitive=False, output_format='integer', ignore_whitespace=False, ignore_special_characters=False):
    # Validate input types
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}
    if not isinstance(letters, list) or not all(isinstance(letter, str) and len(letter) == 1 for letter in letters):
        return {'error': 'letters must be a list of single-character strings'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'case_sensitive must be a boolean'}
    if not isinstance(ignore_whitespace, bool):
        return {'error': 'ignore_whitespace must be a boolean'}
    if not isinstance(ignore_special_characters, bool):
        return {'error': 'ignore_special_characters must be a boolean'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'output_format must be one of ["integer", "text", "detailed"]'}

    # Prepare the input string based on options
    if not case_sensitive:
        input_string = input_string.lower()
        letters = [letter.lower() for letter in letters]
    if ignore_whitespace:
        input_string = input_string.replace(' ', '')
    if ignore_special_characters:
        input_string = ''.join(filter(str.isalnum, input_string))

    # Count occurrences of each letter
    letter_counts = {letter: 0 for letter in letters}
    for char in input_string:
        if char in letter_counts:
            letter_counts[char] += 1

    # Format the output
    if output_format == 'integer':
        return sum(letter_counts.values())
    elif output_format == 'text':
        return ', '.join(f"{letter}: {count}" for letter, count in letter_counts.items())
    elif output_format == 'detailed':
        return letter_counts

