def first_digit_extractor_v2(number: str, ignore_sign: bool = True, ignore_leading_zeros: bool = True, numeral_system: str = 'decimal', complex_number_handling: bool = False) -> str:
    """
    Extracts the first digit from a given number string based on specified rules.

    :param number: The number from which to extract the first digit.
    :param ignore_sign: Whether to ignore the sign of the number.
    :param ignore_leading_zeros: Whether to ignore leading zeros.
    :param numeral_system: The numeral system of the input number.
    :param complex_number_handling: Whether to handle complex numbers by extracting the first digit of the real part.
    :return: The first digit as a string.
    """
    try:
        # Handle complex numbers
        if complex_number_handling:
            if 'j' in number:
                number = number.split('+')[0] if '+' in number else number.split('-')[0]

        # Convert based on numeral system
        if numeral_system == 'binary':
            number = str(int(number, 2))
        elif numeral_system == 'hexadecimal':
            number = str(int(number, 16))

        # Ignore sign
        if ignore_sign and number[0] == '-':
            number = number[1:]

        # Ignore leading zeros
        if ignore_leading_zeros:
            number = number.lstrip('0')

        # Return the first digit
        for char in number:
            if char.isdigit():
                return char

        raise ValueError("No digit found in the input number.")

    except Exception as e:
        return f"Error: {str(e)}"

# Example usage
result = first_digit_extractor_v2('1851')
# Expected output: '1'

def extract_last_digit(number: str, ignore_negative_sign: bool = True, consider_decimal: bool = False, scientific_notation: bool = False, round_decimal: bool = False, digit_position: int = 1) -> str:
    """
    Extract the last digit from a given number based on specified parameters.
    """
    try:
        # Handle scientific notation if specified
        if scientific_notation:
            try:
                number = '{:.15f}'.format(float(number))
            except ValueError:
                return 'Error: Invalid scientific notation format.'

        # Remove negative sign if ignore_negative_sign is True
        if ignore_negative_sign and number.startswith('-'):
            number = number[1:]

        # Consider only the integer part if consider_decimal is False
        if not consider_decimal and '.' in number:
            number = number.split('.')[0]

        # Round the number if round_decimal is True
        if round_decimal:
            try:
                number = str(round(float(number)))
            except ValueError:
                return 'Error: Invalid number format for rounding.'

        # Extract the digit at the specified position from the end
        if digit_position <= 0:
            return 'Error: digit_position must be a positive integer.'

        if len(number) < digit_position:
            return 'Error: digit_position is out of range.'

        return number[-digit_position]
    except Exception as e:
        return f'Error: {str(e)}'

