def extract_first_letter(input, ignore_whitespace=True, case_sensitive=True, ignore_non_alphabetic=False, multi_line=False, detailed_output=False):
    # Helper function to extract the first valid letter from a string
    def get_first_letter(s):
        if ignore_whitespace:
            s = s.lstrip()
        for char in s:
            if ignore_non_alphabetic and not char.isalpha():
                continue
            return char if case_sensitive else char.lower()
        return None

    # Handle multi-line input
    if isinstance(input, str) and multi_line:
        lines = input.splitlines()
        results = [get_first_letter(line) for line in lines]
    elif isinstance(input, str):
        results = [get_first_letter(input)]
    elif isinstance(input, list):
        results = [get_first_letter(item) for item in input]
    else:
        raise ValueError("Invalid input type. Expected a string or a list of strings.")

    # Prepare detailed output if required
    if detailed_output:
        detailed_results = []
        for i, result in enumerate(results):
            if result is not None:
                detailed_results.append({
                    'position': i,
                    'letter': result,
                    'original': input[i] if isinstance(input, list) else input
                })
        return detailed_results

    # Return the first letter found or None
    return results[0] if results else None

