def last_letter_extractor_v2(input, case_format='original', handle_empty='error', non_alpha_handling='include', output_format='single'):
    # Validate input
    if not isinstance(input, list) or len(input) < 1:
        raise ValueError("Input must be a non-empty list of strings.")

    last_letters = []
    for string in input:
        if not isinstance(string, str):
            raise ValueError("All items in the input list must be strings.")

        if string == '':
            if handle_empty == 'error':
                raise ValueError("Empty strings are not allowed.")
            elif handle_empty == 'skip':
                continue
            elif handle_empty == 'empty':
                last_letters.append('')
                continue

        # Extract the last character
        last_char = string[-1]

        # Handle non-alphabetic characters
        if not last_char.isalpha():
            if non_alpha_handling == 'error':
                raise ValueError("Non-alphabetic character found at the end of a string.")
            elif non_alpha_handling == 'exclude':
                # Find the last alphabetic character
                for char in reversed(string):
                    if char.isalpha():
                        last_char = char
                        break
                else:
                    last_char = ''  # No alphabetic character found

        # Adjust case format
        if case_format == 'uppercase':
            last_char = last_char.upper()
        elif case_format == 'lowercase':
            last_char = last_char.lower()

        last_letters.append(last_char)

    # Determine output format
    if output_format == 'single':
        return ''.join(last_letters)
    elif output_format == 'array':
        return last_letters

