def count_characters_advanced(input, ignore_characters=[], ignore_position=[], ignore_types=[], case_sensitive=True, output_format='integer'):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Expected a string.'}

    # Validate ignore_characters parameter
    if not all(isinstance(char, str) and len(char) == 1 for char in ignore_characters):
        return {'error': 'Invalid ignore_characters. Expected an array of single-character strings.'}

    # Validate ignore_position parameter
    valid_positions = {'first', 'last', 'even', 'odd'}
    if not all(pos in valid_positions for pos in ignore_position):
        return {'error': 'Invalid ignore_position. Expected values: first, last, even, odd.'}

    # Validate ignore_types parameter
    valid_types = {'digits', 'punctuation', 'whitespace'}
    if not all(typ in valid_types for typ in ignore_types):
        return {'error': 'Invalid ignore_types. Expected values: digits, punctuation, whitespace.'}

    # Validate case_sensitive parameter
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive value. Expected a boolean.'}

    # Validate output_format parameter
    valid_formats = {'integer', 'text', 'detailed'}
    if output_format not in valid_formats:
        return {'error': 'Invalid output_format. Expected values: integer, text, detailed.'}

    # Prepare the input string based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Initialize character count
    char_count = 0
    char_distribution = {}

    # Iterate over the string and count characters
    for i, char in enumerate(input):
        # Check ignore_characters
        if char in ignore_characters:
            continue

        # Check ignore_position
        if ('first' in ignore_position and i == 0) or \
           ('last' in ignore_position and i == len(input) - 1) or \
           ('even' in ignore_position and i % 2 == 0) or \
           ('odd' in ignore_position and i % 2 != 0):
            continue

        # Check ignore_types
        if ('digits' in ignore_types and char.isdigit()) or \
           ('punctuation' in ignore_types and char in '.,;!?') or \
           ('whitespace' in ignore_types and char.isspace()):
            continue

        # Count the character
        char_count += 1
        char_distribution[char] = char_distribution.get(char, 0) + 1

    # Format the output
    if output_format == 'integer':
        return char_count
    elif output_format == 'text':
        return f'Total characters counted: {char_count}'
    elif output_format == 'detailed':
        return {'total_count': char_count, 'distribution': char_distribution}

