def string_length_counter(input: str, ignore_characters: list = [], ignore_position: list = [], case_sensitive: bool = False, ignore_whitespace: bool = False, count_character_types: list = [], output_format: str = 'integer') -> int:
    # Error handling for input type
    if not isinstance(input, str):
        raise ValueError('Input must be a string.')
    if not isinstance(ignore_characters, list) or not all(isinstance(char, str) for char in ignore_characters):
        raise ValueError('Ignore characters must be a list of strings.')
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        raise ValueError('Ignore position must be a list containing "first" or "last".')
    if not isinstance(case_sensitive, bool):
        raise ValueError('Case sensitive must be a boolean.')
    if not isinstance(ignore_whitespace, bool):
        raise ValueError('Ignore whitespace must be a boolean.')
    if not isinstance(count_character_types, list) or not all(type in ['vowels', 'consonants', 'digits', 'special'] for type in count_character_types):
        raise ValueError('Count character types must be a list containing "vowels", "consonants", "digits", or "special".')
    if output_format not in ['integer', 'text', 'detailed']:
        raise ValueError('Output format must be "integer", "text", or "detailed".')

    # Adjust input based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Remove ignored characters
    input = ''.join(char for char in input if char not in ignore_characters)

    # Remove whitespace if specified
    if ignore_whitespace:
        input = input.replace(' ', '')

    # Remove characters based on position
    if 'first' in ignore_position and input:
        input = input[1:]
    if 'last' in ignore_position and input:
        input = input[:-1]

    # Count characters
    count = len(input)

    # Output formatting
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The string has {count} characters.'
    elif output_format == 'detailed':
        # Detailed breakdown (not needed for this question)
        return {
            'total': count,
            'vowels': sum(1 for char in input if char in 'aeiou'),
            'consonants': sum(1 for char in input if char.isalpha() and char not in 'aeiou'),
            'digits': sum(1 for char in input if char.isdigit()),
            'special': sum(1 for char in input if not char.isalnum())
        }

