def advanced_arithmetic_calculator(numbers, operation='add', handle_division_by_zero='error'):
    """
    Perform arithmetic operations on a list of numbers.

    Parameters:
    - numbers (list of float): A list of numbers to perform the operation on.
    - operation (str): The operation to perform ('add', 'subtract', 'multiply', 'divide', 'exponentiate', 'modulus').
    - handle_division_by_zero (str): How to handle division by zero ('error', 'infinity', 'zero').

    Returns:
    - float: The result of the arithmetic operation.
    """
    if len(numbers) < 2:
        raise ValueError("At least two numbers are required.")

    if operation not in ['add', 'subtract', 'multiply', 'divide', 'exponentiate', 'modulus']:
        raise ValueError("Invalid operation specified.")

    result = numbers[0]

    for num in numbers[1:]:
        if operation == 'add':
            result += num
        elif operation == 'subtract':
            result -= num
        elif operation == 'multiply':
            result *= num
        elif operation == 'divide':
            if num == 0:
                if handle_division_by_zero == 'error':
                    raise ZeroDivisionError("Division by zero encountered.")
                elif handle_division_by_zero == 'infinity':
                    return float('inf')
                elif handle_division_by_zero == 'zero':
                    return 0
            else:
                result /= num
        elif operation == 'exponentiate':
            result **= num
        elif operation == 'modulus':
            if num == 0:
                if handle_division_by_zero == 'error':
                    raise ZeroDivisionError("Division by zero encountered.")
                elif handle_division_by_zero == 'infinity':
                    return float('inf')
                elif handle_division_by_zero == 'zero':
                    return 0
            else:
                result %= num

    return result

