            last_name = parts[-1]  # Default to western for simplicity

        # Include middle names if specified
        if include_middle_names and len(parts) > 2:
            last_name = ' '.join(parts[1:]) if naming_convention == 'western' else ' '.join(parts[:-1])

        return last_name
    except IndexError:
        if error_handling == 'warn':
            print('Warning: Unable to extract last name due to insufficient parts.')
            return None
        elif error_handling == 'strict':
            raise ValueError('Error: Unable to extract last name due to insufficient parts.')
