def extract_character(input: str, position: str, custom_index: int = None, indices: list = None, case_sensitive: bool = True, trim_whitespace: bool = False):
    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Handle case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Extract character based on position
    if position == 'first':
        return input[0] if input else ''
    elif position == 'last':
        return input[-1] if input else ''
    elif position == 'custom':
        if custom_index is None:
            raise ValueError("'custom_index' must be provided when position is 'custom'.")
        if abs(custom_index) >= len(input):
            raise IndexError('custom_index out of range.')
        return input[custom_index]
    elif position == 'multiple':
        if indices is None:
            raise ValueError("'indices' must be provided when position is 'multiple'.")
        return ''.join(input[i] for i in indices if abs(i) < len(input))
    else:
        raise ValueError('Invalid position value.')

