                string = ''.join([char for i, char in enumerate(string) if i % 2 == 0])

        # Count characters
        count = len(string)
        total_count += count

        # Count specific characters separately
        specific_counts = {}
        if count_characters:
            for char in count_characters:
                specific_counts[char] = string.count(char)

        # Add to detailed report
        detailed_report.append({'string': string, 'count': count, 'specific_counts': specific_counts})

    # Format output
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total character count: {total_count}'
    elif output_format == 'detailed_report':
        return detailed_report
    else:
