def extract_name_components(names, output_format='string', components=['first'], handle_errors=True, log_level='error'):
    """
    Extract specified components from full names.

    :param names: List of full names to process.
    :param output_format: Desired format of the output.
    :param components: List of name components to extract.
    :param handle_errors: Enable or disable error handling.
    :param log_level: Set the logging level.
    :return: Extracted name components in the specified format.
    """
    def log(message, level):
        if log_level == 'debug' or (log_level == 'info' and level in ['info', 'error']) or (log_level == 'error' and level == 'error'):
            print(f"[{level.upper()}] {message}")

    if handle_errors:
        if not names or not isinstance(names, list) or not all(isinstance(name, str) for name in names):
            log("Invalid input: 'names' must be a list of strings.", 'error')
            return "Error: Invalid input."

    extracted_names = []
    for full_name in names:
        parts = full_name.split()
        name_dict = {'first': parts[0] if len(parts) > 0 else '',
                     'middle': ' '.join(parts[1:-1]) if len(parts) > 2 else '',
                     'last': parts[-1] if len(parts) > 1 else ''}
        extracted = [name_dict[comp] for comp in components if comp in name_dict]
        if output_format == 'string':
            extracted_names.append(' '.join(extracted))
        elif output_format == 'array':
            extracted_names.append(extracted)
        elif output_format == 'object':
            extracted_names.append({comp: name_dict[comp] for comp in components})

    if len(extracted_names) == 1 and output_format == 'string':
        return extracted_names[0]
    return extracted_names

