    # Error handling for invalid 'handle_empty' parameter
    if handle_empty not in ['return_empty', 'error']:
        return {'error': "Invalid value for 'handle_empty'. Must be 'return_empty' or 'error'."}

    # Error handling for invalid 'character_set' parameter
    if character_set not in ['alphabetic', 'alphanumeric', 'any']:
        return {'error': "Invalid value for 'character_set'. Must be 'alphabetic', 'alphanumeric', or 'any'."}

    # Handle empty input
    if not input:
        if handle_empty == 'return_empty':
            return {'result': ''}
        else:
            return {'error': 'Input string is empty.'}

    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Define character sets
    import string
    if character_set == 'alphabetic':
        valid_chars = string.ascii_letters
    elif character_set == 'alphanumeric':
        valid_chars = string.ascii_letters + string.digits
    else:
        valid_chars = None  # 'any' means no restriction

    # Extract first letter based on parameters
    def extract_first_letter(s):
        for char in s:
            if valid_chars is None or char in valid_chars:
                return char if case_sensitive else char.lower()
        return ''

    # Handle multiple extraction
    if multiple_extraction:
        words = input.split()
        return {'result': [extract_first_letter(word) for word in words]}
    else:
        return {'result': extract_first_letter(input)}

