    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name. It must be a non-empty string.'}

    # Error handling for optional parameters
    if not isinstance(delimiter, str):
        return {'error': 'Invalid delimiter. It must be a string.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive. It must be a boolean.'}
    if output_format not in ['string', 'json', 'array']:
        return {'error': 'Invalid output_format. It must be one of: string, json, array.'}
    if not isinstance(include_middle_name, bool):
        return {'error': 'Invalid include_middle_name. It must be a boolean.'}
    if not isinstance(include_suffix, bool):
        return {'error': 'Invalid include_suffix. It must be a boolean.'}
    if not isinstance(include_prefix, bool):
        return {'error': 'Invalid include_prefix. It must be a boolean.'}

    # Split the full name using the delimiter
    name_parts = full_name.split(delimiter)

    # Handle case sensitivity
    if not case_sensitive:
        name_parts = [part.lower() for part in name_parts]

    # Extract name components
    prefix = name_parts[0] if include_prefix and len(name_parts) > 2 else ''
    first_name = name_parts[1] if include_prefix and len(name_parts) > 2 else name_parts[0]
    middle_name = name_parts[2] if include_middle_name and len(name_parts) > 3 else ''
    last_name = name_parts[-1] if len(name_parts) > 1 else ''
    suffix = name_parts[-1] if include_suffix and len(name_parts) > 2 else ''

    # Prepare the output based on the output_format
    if output_format == 'string':
        return first_name
    elif output_format == 'json':
        return {
            'prefix': prefix,
            'first_name': first_name,
            'middle_name': middle_name,
            'last_name': last_name,
            'suffix': suffix
        }
    elif output_format == 'array':
        return [prefix, first_name, middle_name, last_name, suffix]

