def extract_first_name(full_name, ignore_prefixes=True, ignore_suffixes=True, case_sensitive=False, handle_middle_names=False, handle_compound_names=True, output_format='first'):
    # Error handling for incorrect input types
    if not isinstance(full_name, str):
        return {'error': 'Invalid input: full_name must be a string.'}
    if output_format not in ['first', 'first_initial']:
        return {'error': 'Invalid input: output_format must be either "first" or "first_initial".'}

    # List of common prefixes and suffixes
    prefixes = ['Dr.', 'Mr.', 'Ms.'] if ignore_prefixes else []
    suffixes = ['Jr.', 'Sr.', 'III'] if ignore_suffixes else []

    # Split the full name into parts
    name_parts = full_name.split()

    # Remove prefixes
    if ignore_prefixes and name_parts[0] in prefixes:
        name_parts = name_parts[1:]

    # Remove suffixes
    if ignore_suffixes and name_parts[-1] in suffixes:
        name_parts = name_parts[:-1]

    # Handle compound names
    if handle_compound_names and len(name_parts) > 1:
        first_name = name_parts[0]
        if '-' in first_name or ' ' in full_name:
            first_name = ' '.join(name_parts[:2])
    else:
        first_name = name_parts[0]

    # Handle middle names
    if handle_middle_names and len(name_parts) > 2:
        first_name = name_parts[0] + ' ' + name_parts[1]

    # Apply case sensitivity
    if not case_sensitive:
        first_name = first_name.capitalize()

    # Format output
    if output_format == 'first_initial':
        first_name = first_name[0] + '.'

    return {'first_name': first_name}

