def extract_last_letter(input, ignore_whitespace=True, output_format='character', handle_empty_strings='skip', non_alphabetic_handling='include'):
    # Validate input
    if not isinstance(input, list) or not all(isinstance(i, str) for i in input):
        raise ValueError("Input must be a list of strings.")
    if len(input) < 1 or len(input) > 20:
        raise ValueError("Input list must contain between 1 and 20 strings.")

    # Prepare the result list
    results = []

    for string in input:
        # Handle empty strings
        if string == '':
            if handle_empty_strings == 'error':
                raise ValueError("Empty string encountered.")
            elif handle_empty_strings == 'null':
                results.append(None)
                continue
            elif handle_empty_strings == 'skip':
                continue

        # Ignore trailing whitespace if specified
        if ignore_whitespace:
            string = string.rstrip()

        # Extract the last character
        if string:
            last_char = string[-1]

            # Handle non-alphabetic characters
            if not last_char.isalpha():
                if non_alphabetic_handling == 'exclude':
                    last_char = next((c for c in reversed(string) if c.isalpha()), None)
                elif non_alphabetic_handling == 'error':
                    raise ValueError("Non-alphabetic character encountered as last character.")

            if last_char is None:
                continue

            # Append result based on output format
            if output_format == 'character':
                results.append(last_char)
            elif output_format == 'text':
                results.append(f"The last letter is {last_char}.")
            elif output_format == 'json':
                results.append({"last_letter": last_char})
            else:
                raise ValueError("Unsupported output format.")

    # Return results
    if output_format == 'json':
        return results
    elif output_format == 'text':
        return ' '.join(results)
    else:
        return results

