def distinct_combinations(input_string, combination_length=2, case_sensitive=False, output_format='count', ignore_special_characters=True):
    # Validate input_string
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}

    # Validate combination_length
    if not isinstance(combination_length, int) or combination_length < 2:
        return {'error': 'combination_length must be an integer greater than or equal to 2'}

    # Validate output_format
    if output_format not in ['count', 'list', 'detailed']:
        return {'error': "output_format must be one of ['count', 'list', 'detailed']"}

    # Process input_string based on ignore_special_characters
    if ignore_special_characters:
        input_string = ''.join(filter(str.isalnum, input_string))

    # Adjust case sensitivity
    if not case_sensitive:
        input_string = input_string.lower()

    # Generate combinations
    from itertools import combinations
    comb_set = set(''.join(comb) for comb in combinations(input_string, combination_length))

    # Prepare output
    if output_format == 'count':
        return len(comb_set)
    elif output_format == 'list':
        return list(comb_set)
    elif output_format == 'detailed':
        from collections import Counter
        comb_counter = Counter(''.join(comb) for comb in combinations(input_string, combination_length))
        return {'total': len(comb_set), 'details': comb_counter}

