    elif character_set == 'custom':
        valid_chars = set(custom_character_set)

    # Adjust for case sensitivity
    if not case_sensitive:
        input = input.lower()
        valid_chars = set(char.lower() for char in valid_chars)
        ignore_characters = [char.lower() for char in ignore_characters]

    # Remove ignored characters
    input = ''.join(char for char in input if char not in ignore_characters)

    # Remove ignored positions
    if 'first' in ignore_position and len(input) > 0:
        input = input[1:]
    if 'last' in ignore_position and len(input) > 0:
        input = input[:-1]

    # Count valid characters
    count = 0
    detailed_count = {}
    for char in input:
