def extract_last_name(full_name, output_format='string', handle_special_characters=False, include_middle_name=False, include_suffix=False, include_prefix=False):
    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid input: full_name must be a non-empty string.'}

    # Split the full name into parts
    name_parts = full_name.split()

    # Handle special characters if required
    if handle_special_characters:
        name_parts = [part.normalize('NFKD').encode('ascii', 'ignore').decode('utf-8') for part in name_parts]

    # Determine the last name
    last_name = name_parts[-1] if name_parts else ''

    # Include middle name if required
    if include_middle_name and len(name_parts) > 2:
        last_name = ' '.join(name_parts[1:])

    # Include prefix if required
    if include_prefix and len(name_parts) > 1:
        last_name = name_parts[0] + ' ' + last_name

    # Include suffix if required
    if include_suffix and len(name_parts) > 2:
        last_name += ' ' + name_parts[-1]

    # Format the output based on the output_format parameter
    if output_format == 'array':
        return name_parts
    elif output_format == 'object':
        return {
            'prefix': name_parts[0] if include_prefix and len(name_parts) > 1 else '',
            'first_name': name_parts[0] if len(name_parts) > 0 else '',
            'middle_name': ' '.join(name_parts[1:-1]) if include_middle_name and len(name_parts) > 2 else '',
            'last_name': last_name,
            'suffix': name_parts[-1] if include_suffix and len(name_parts) > 2 else ''
        }
    else:  # Default to string
        return last_name

