def string_length_counter(input, ignore_characters=[], case_sensitive=False, character_types=['letters'], output_format='integer'):
    # Validate input types
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(ignore_characters, list) or not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'Ignore characters must be a list of strings.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Case sensitive flag must be a boolean.'}
    if not isinstance(character_types, list) or not all(char_type in ['letters', 'digits', 'symbols'] for char_type in character_types):
        return {'error': 'Character types must be a list containing any of: letters, digits, symbols.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Output format must be one of: integer, text, detailed.'}

    # Prepare the input string based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Filter characters based on ignore list and character types
    filtered_input = ''.join(
        char for char in input
        if char not in ignore_characters and
           ((char.isalpha() and 'letters' in character_types) or
            (char.isdigit() and 'digits' in character_types) or
            (not char.isalnum() and 'symbols' in character_types))
    )

    # Count the characters
    count = len(filtered_input)

    # Prepare the output based on the format
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The count is {count}.'
    elif output_format == 'detailed':
        ignored_count = len(input) - len(filtered_input)
        ignored_percentage = (ignored_count / len(input)) * 100 if len(input) > 0 else 0
        return {
            'count': count,
            'ignored_characters': ignored_count,
            'ignored_percentage': ignored_percentage
        }

