def reverse_order(input, output_format='string', reverse_scope='full', partial_indices=None):
    # Validate input
    if not isinstance(input, (str, int, float)):
        return {'error': 'Invalid input type. Input must be a string or number.'}

    # Convert input to string for processing
    input_str = str(input)

    # Handle reverse_scope
    if reverse_scope == 'full':
        reversed_str = input_str[::-1]
    elif reverse_scope == 'partial':
        if not partial_indices or len(partial_indices) != 2:
            return {'error': 'partial_indices must be provided as an array of two integers for partial reversal.'}
        start, end = partial_indices
        if not (0 <= start < end <= len(input_str)):
            return {'error': 'Invalid partial_indices. Ensure 0 <= start < end <= length of input.'}
        # Reverse the specified section
        reversed_str = input_str[:start] + input_str[start:end][::-1] + input_str[end:]
    else:
        return {'error': 'Invalid reverse_scope. Must be either "full" or "partial".'}

    # Handle output_format
    if output_format == 'string':
        return reversed_str
    elif output_format == 'number':
        try:
            return int(reversed_str)
        except ValueError:
            return {'error': 'Reversed result cannot be converted to a number.'}
    elif output_format == 'json':
        return {'reversed': reversed_str}
    elif output_format == 'array':
        return list(reversed_str)
    else:
        return {'error': 'Invalid output_format. Must be one of "string", "number", "json", "array".'}

