def digit_product_calculator_v2(number, ignore_zeros=False, output_format='integer', digit_range=None, round_result=False):
    # Validate the 'number' parameter
    if not isinstance(number, int) or number < 0:
        return {'error': 'Invalid input: number must be a non-negative integer.'}

    # Convert the number to a string to iterate over digits
    digits = str(number)

    # Initialize the product
    product = 1

    # Prepare detailed output if needed
    detailed_steps = []

    # Iterate over each digit
    for digit in digits:
        digit_int = int(digit)

        # Apply digit range filter if specified
        if digit_range is not None and digit_int not in digit_range:
            continue

        # Ignore zeros if specified
        if ignore_zeros and digit_int == 0:
            continue

        # Multiply the product by the current digit
        product *= digit_int

        # Record the step if detailed output is required
        if output_format == 'detailed':
            detailed_steps.append(f'Multiply by {digit_int}, product is now {product}')

    # Round the result if specified
    if round_result:
        product = round(product)

    # Prepare the output based on the specified format
    if output_format == 'integer':
        return product
    elif output_format == 'text':
        return f'The product of the digits is {product}'
    elif output_format == 'detailed':
        return {'product': product, 'steps': detailed_steps}
    else:
        return {'error': 'Invalid output format specified.'}

