def consonant_counter(input, case_sensitive=False, output_format='integer', language='en', exclude_consonants=[]):
    # Define consonant sets for supported languages
    consonants = {
        'en': 'bcdfghjklmnpqrstvwxyz',
        'es': 'bcdfghjklmnñpqrstvwxyz',
        'fr': 'bcdfghjklmnpqrstvwxyz',
        'de': 'bcdfghjklmnpqrstvwxyz'
    }

    # Validate input parameters
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Case_sensitive must be a boolean.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format. Choose from integer, text, detailed.'}
    if language not in consonants:
        return {'error': 'Unsupported language. Choose from en, es, fr, de.'}
    if not all(isinstance(c, str) and len(c) == 1 and c in consonants['en'] for c in exclude_consonants):
        return {'error': 'Exclude_consonants must be a list of single consonant characters.'}

    # Adjust consonants based on case sensitivity
    if not case_sensitive:
        input = input.lower()
        exclude_consonants = [c.lower() for c in exclude_consonants]

    # Get the relevant consonant set and exclude specified consonants
    consonant_set = set(consonants[language]) - set(exclude_consonants)

    # Count consonants
    consonant_count = {}
    for char in input:
        if char in consonant_set:
            consonant_count[char] = consonant_count.get(char, 0) + 1

    # Format output
    if output_format == 'integer':
        return sum(consonant_count.values())
    elif output_format == 'text':
        return f'There are {sum(consonant_count.values())} consonants.'
    elif output_format == 'detailed':
        return consonant_count

# Example usage based on the question
result = consonant_counter('Ringo')
# Expected output: 3

def extract_last_name(full_name, name_delimiter=' ', ignore_titles=True, cultural_context='western', include_middle_name=False, handle_suffixes=True, custom_rules=None):
    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name. It must be a non-empty string.'}

    # Error handling for cultural context
    if cultural_context not in ['western', 'eastern', 'arabic', 'custom']:
        return {'error': 'Invalid cultural_context. Must be one of: western, eastern, arabic, custom.'}

    # Split the full name using the specified delimiter
    name_parts = full_name.split(name_delimiter)

    # Handle titles if ignore_titles is True
    if ignore_titles:
        titles = ['Dr.', 'Mr.', 'Ms.', 'Mrs.']
        if custom_rules and 'title_list' in custom_rules:
            titles.extend(custom_rules['title_list'])
        name_parts = [part for part in name_parts if part not in titles]

    # Handle suffixes if handle_suffixes is True
    if handle_suffixes:
        suffixes = ['Jr.', 'Sr.', 'II', 'III']
        if custom_rules and 'suffix_list' in custom_rules:
            suffixes.extend(custom_rules['suffix_list'])
        if name_parts[-1] in suffixes:
            name_parts.pop()

    # Determine the last name based on cultural context
    last_name = ''
    if cultural_context == 'western':
        last_name = name_parts[-1]
    elif cultural_context == 'eastern':
        last_name = name_parts[0]
    elif cultural_context == 'arabic':
        # Assuming 'al-' as a common prefix in Arabic names
        last_name = next((part for part in name_parts if 'al-' in part), name_parts[-1])
    elif cultural_context == 'custom' and custom_rules:
        # Custom parsing logic can be implemented here
        last_name = name_parts[-1]  # Default to last part if no custom logic

    # Include middle name if specified
    if include_middle_name and len(name_parts) > 2:
        middle_name = name_parts[1:-1] if cultural_context == 'western' else name_parts[1:]
        last_name = ' '.join(middle_name + [last_name])

    return {'last_name': last_name}

# Example usage
result = extract_last_name('Rukn al-Dawla', cultural_context='arabic')
print(result)  # Expected output: {'last_name': 'al-Dawla'}

def count_repeated_letters_v2(input, case_sensitive=False, include_special_characters=False, character_types=['letters'], output_format='summary', ignore_whitespace=True):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}

    # Validate character_types parameter
    valid_character_types = {'letters', 'digits', 'special'}
    if not all(ct in valid_character_types for ct in character_types):
        return {'error': 'Invalid character type specified.'}

    # Validate output_format parameter
    if output_format not in {'summary', 'detailed'}:
        return {'error': 'Invalid output format specified.'}

    # Prepare the string for analysis
    if not case_sensitive:
        input = input.lower()

    # Filter characters based on character_types
    filtered_input = ''
    for char in input:
        if 'letters' in character_types and char.isalpha():
            filtered_input += char
        elif 'digits' in character_types and char.isdigit():
            filtered_input += char
        elif 'special' in character_types and not char.isalnum():
            filtered_input += char

    # Ignore whitespace if specified
    if ignore_whitespace:
        filtered_input = filtered_input.replace(' ', '')

    # Count repeated characters
    from collections import Counter
    char_count = Counter(filtered_input)
    repeated_count = {char: count for char, count in char_count.items() if count > 1}

    # Prepare output
    if output_format == 'summary':
        return {'repeated_count': sum(repeated_count.values())}
    elif output_format == 'detailed':
        return {'repeated_details': repeated_count}

    return {'error': 'Unexpected error occurred.'}

