def vowel_counter(inputs, vowels_to_count=None, ignore_case=True, language='en', detailed_output=False):
    # Default vowels to count if not specified
    if vowels_to_count is None:
        vowels_to_count = ['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']

    # Validate inputs
    if not isinstance(inputs, list) or not all(isinstance(i, str) for i in inputs):
        return {'error': 'Invalid input: inputs must be a list of strings.'}
    if not isinstance(vowels_to_count, list) or not all(v in ['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'] for v in vowels_to_count):
        return {'error': 'Invalid vowels_to_count: must be a list of specified vowels.'}
    if language not in ['en', 'es', 'fr', 'de']:
        return {'error': 'Unsupported language. Supported languages are en, es, fr, de.'}
    if not isinstance(ignore_case, bool) or not isinstance(detailed_output, bool):
        return {'error': 'Invalid parameter: ignore_case and detailed_output must be boolean values.'}

    # Prepare vowels set for counting
    if ignore_case:
        vowels_to_count = set(v.lower() for v in vowels_to_count)
    else:
        vowels_to_count = set(vowels_to_count)

    # Initialize count
    total_count = 0
    detailed_counts = {v: 0 for v in vowels_to_count} if detailed_output else None

    # Count vowels
    for string in inputs:
        for char in string:
            char_to_check = char.lower() if ignore_case else char
            if char_to_check in vowels_to_count:
                total_count += 1
                if detailed_output:
                    detailed_counts[char_to_check] += 1

    # Return result
    if detailed_output:
        return {'total_count': total_count, 'detailed_counts': detailed_counts}
    else:
        return {'total_count': total_count}

