        combined_input = ''.join(inputs)
        result = count_vowels(combined_input)
    else:
        result = [count_vowels(s) for s in inputs]

    # Format output
    if output_format == 'integer':
        if batch_processing:
            return sum(result.values())
        else:
            return [sum(r.values()) for r in result]
    elif output_format == 'text':
        if batch_processing:
            return f'Total vowels: {sum(result.values())}'
        else:
            return [f'Total vowels in string {i+1}: {sum(r.values())}' for i, r in enumerate(result)]
    elif output_format == 'detailed':
        return result

