def advanced_consonant_counter(input: str, ignore_characters: list = None, ignore_position: list = None, case_sensitive: bool = False, language: str = 'en', custom_consonants: list = None, detailed_statistics: bool = False):
    # Define consonants based on language
    consonants = {
        'en': 'bcdfghjklmnpqrstvwxyz',
        'es': 'bcdfghjklmnñpqrstvwxyz',
        'fr': 'bcdfghjklmnpqrstvwxyz',
        'de': 'bcdfghjklmnpqrstvwxyzß',
        'custom': ''.join(custom_consonants) if custom_consonants else ''
    }

    # Validate input
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if language not in consonants:
        return {'error': 'Unsupported language specified.'}
    if language == 'custom' and not custom_consonants:
        return {'error': 'Custom consonants must be provided for custom language.'}

    # Adjust consonants for case sensitivity
    if not case_sensitive:
        input = input.lower()
        consonants = {lang: chars.lower() for lang, chars in consonants.items()}

    # Initialize consonant count
    consonant_count = 0
    consonant_freq = {}

    # Iterate over input string
    for i, char in enumerate(input):
        # Ignore specified characters
        if ignore_characters and char in ignore_characters:
            continue
        # Ignore specified positions
        if ignore_position:
            if ('first' in ignore_position and i == 0) or \
               ('last' in ignore_position and i == len(input) - 1) or \
               ('even' in ignore_position and i % 2 == 0) or \
               ('odd' in ignore_position and i % 2 != 0):
                continue
        # Count consonants
        if char in consonants[language]:
            consonant_count += 1
            if detailed_statistics:
                if char in consonant_freq:
                    consonant_freq[char] += 1
                else:
                    consonant_freq[char] = 1

    # Return results
    result = {'total_consonants': consonant_count}
    if detailed_statistics:
        result['detailed_statistics'] = consonant_freq
    return result

