def extract_last_letter(input, output_format='character', case='original', separator='', handle_empty='ignore', default_character=''):
    # Validate input
    if not isinstance(input, list) or len(input) < 1:
        raise ValueError("Input must be a list with at least one string.")
    if output_format not in ['character', 'text']:
        raise ValueError("Invalid output_format. Must be 'character' or 'text'.")
    if case not in ['original', 'uppercase', 'lowercase']:
        raise ValueError("Invalid case. Must be 'original', 'uppercase', or 'lowercase'.")
    if handle_empty not in ['ignore', 'error', 'default']:
        raise ValueError("Invalid handle_empty. Must be 'ignore', 'error', or 'default'.")

    # Process each string in the input list
    result = []
    for string in input:
        if not string:
            if handle_empty == 'error':
                raise ValueError("Empty string encountered and handle_empty is set to 'error'.")
            elif handle_empty == 'default':
                last_letter = default_character
            else:  # handle_empty == 'ignore'
                continue
        else:
            last_letter = string[-1]

        # Apply case transformation
        if case == 'uppercase':
            last_letter = last_letter.upper()
        elif case == 'lowercase':
            last_letter = last_letter.lower()

        result.append(last_letter)

    # Join the result with the specified separator
    output = separator.join(result)

    # Adjust output format if needed
    if output_format == 'text':
        output = ' '.join(result)

    return output

