def count_boolean_values(input, target_value=True, output_format='integer', count_consecutive=False, case_sensitive=False):
    # Validate input
    if not isinstance(input, list) or not all(isinstance(i, bool) for i in input):
        return {'error': 'Input must be a list of boolean values.'}
    if output_format not in ['integer', 'text', 'json', 'detailed_report']:
        return {'error': 'Invalid output format specified.'}

    # Initialize count
    count = 0
    consecutive_count = 0
    max_consecutive = 0

    # Count occurrences
    for value in input:
        if value == target_value:
            count += 1
            consecutive_count += 1
        else:
            max_consecutive = max(max_consecutive, consecutive_count)
            consecutive_count = 0
    max_consecutive = max(max_consecutive, consecutive_count)

    # Determine final count based on count_consecutive
    final_count = max_consecutive if count_consecutive else count

    # Format output
    if output_format == 'integer':
        return final_count
    elif output_format == 'text':
        return f'The count of {target_value} is {final_count}.'
    elif output_format == 'json':
        return {'count': final_count}
    elif output_format == 'detailed_report':
        return {
            'total_count': count,
            'max_consecutive_count': max_consecutive,
            'target_value': target_value,
            'input_length': len(input)
        }

