def sum_digits(number, ignore_digits=None, ignore_digit_ranges=None, ignore_position=None, handle_negative=True, output_format='integer'):
    """
    Calculate the sum of digits in a number with options to ignore specific digits, ranges, or positions.
    """
    # Error handling for invalid number type
    if not isinstance(number, (int, float)):
        return {'error': 'Invalid number type. Must be an integer or float.'}

    # Handle negative numbers if required
    if handle_negative:
        number = abs(number)

    # Convert number to string to iterate over digits
    number_str = str(number).replace('.', '')  # Remove decimal point for processing

    # Initialize sum
    total_sum = 0

    # Iterate over each digit
    for i, digit in enumerate(number_str):
        digit_int = int(digit)

        # Check if digit should be ignored
        if ignore_digits and digit_int in ignore_digits:
            continue

        # Check if digit is in any ignore range
        if ignore_digit_ranges:
            in_range = any(start <= digit_int <= end for start, end in [(r['start'], r['end']) for r in ignore_digit_ranges])
            if in_range:
                continue

        # Check if position should be ignored
        if ignore_position:
            if ('first' in ignore_position and i == 0) or \
               ('last' in ignore_position and i == len(number_str) - 1) or \
               ('even' in ignore_position and i % 2 == 0) or \
               ('odd' in ignore_position and i % 2 != 0):
                continue

        # Add digit to sum
        total_sum += digit_int

    # Format output
    if output_format == 'text':
        return f'The sum of digits is {total_sum}'
    elif output_format == 'json':
        return {'sum': total_sum}
    elif output_format == 'xml':
        return f'<sum>{total_sum}</sum>'
    else:
        return total_sum

