def enhanced_combined_length_calculator(input, ignore_characters=None, ignore_position=None, case_sensitive=False, handle_whitespace='count', special_characters=True, output_format='integer'):
    # Validate input
    if not isinstance(input, list) or len(input) < 2:
        return {'error': 'Input must be an array with at least two strings.'}

    # Initialize total length
    total_length = 0

    # Process each string
    for string in input:
        # Handle case sensitivity
        if not case_sensitive:
            string = string.lower()

        # Handle whitespace
        if handle_whitespace == 'ignore':
            string = string.replace(' ', '')
        elif handle_whitespace == 'trim':
            string = string.strip()

        # Ignore specified characters
        if ignore_characters:
            for char in ignore_characters:
                string = string.replace(char, '')

        # Calculate length considering special characters
        if not special_characters:
            string = ''.join(filter(str.isalnum, string))

        # Ignore specified positions
        if ignore_position:
            if 'first' in ignore_position and len(string) > 0:
                string = string[1:]
            if 'last' in ignore_position and len(string) > 0:
                string = string[:-1]
            if 'middle' in ignore_position and len(string) > 2:
                mid_index = len(string) // 2
                string = string[:mid_index] + string[mid_index+1:]

        # Add to total length
        total_length += len(string)

    # Format output
    if output_format == 'integer':
        return total_length
    elif output_format == 'text':
        return f'The combined length is {total_length}.'
    elif output_format == 'detailed':
        details = {s: len(s) for s in input}
        return {'total_length': total_length, 'details': details}
    else:
        return {'error': 'Invalid output format specified.'}

