def enhanced_unique_character_counter(input_string, ignore_case=True, include_non_letters=False, character_set='letters', counting_method='absolute', output_format='integer'):
    # Validate input types
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string.'}
    if not isinstance(ignore_case, bool):
        return {'error': 'ignore_case must be a boolean.'}
    if not isinstance(include_non_letters, bool):
        return {'error': 'include_non_letters must be a boolean.'}
    if character_set not in ['letters', 'digits', 'symbols', 'all']:
        return {'error': "character_set must be one of ['letters', 'digits', 'symbols', 'all']."}
    if counting_method not in ['absolute', 'relative']:
        return {'error': "counting_method must be one of ['absolute', 'relative']."}
    if output_format not in ['integer', 'list', 'detailed']:
        return {'error': "output_format must be one of ['integer', 'list', 'detailed']."}

    # Prepare the string based on ignore_case
    if ignore_case:
        input_string = input_string.lower()

    # Filter characters based on character_set
    if character_set == 'letters':
        filtered_chars = [c for c in input_string if c.isalpha()]
    elif character_set == 'digits':
        filtered_chars = [c for c in input_string if c.isdigit()]
    elif character_set == 'symbols':
        filtered_chars = [c for c in input_string if not c.isalnum()]
    else:  # 'all'
        filtered_chars = list(input_string)

    # Include non-letters if specified
    if include_non_letters:
        filtered_chars = list(input_string)

    # Count unique characters
    unique_chars = set(filtered_chars)
    unique_count = len(unique_chars)

    # Calculate relative count if needed
    if counting_method == 'relative':
        total_chars = len(filtered_chars)
        unique_count = (unique_count / total_chars) * 100 if total_chars > 0 else 0

    # Format output
    if output_format == 'integer':
        return unique_count
    elif output_format == 'list':
        return list(unique_chars)
    elif output_format == 'detailed':
        return {char: filtered_chars.count(char) for char in unique_chars}

