    if not isinstance(delimiter, str):
        return {'error': 'Invalid input: delimiter must be a string.'}
    if not isinstance(handle_special_characters, bool):
        return {'error': 'Invalid input: handle_special_characters must be a boolean.'}
    if not isinstance(include_middle_names, bool):
        return {'error': 'Invalid input: include_middle_names must be a boolean.'}
    if not isinstance(suffix_handling, bool):
        return {'error': 'Invalid input: suffix_handling must be a boolean.'}
    if not isinstance(prefix_handling, bool):
        return {'error': 'Invalid input: prefix_handling must be a boolean.'}
    if not isinstance(character_encoding, str):
        return {'error': 'Invalid input: character_encoding must be a string.'}

    # Split the full name using the specified delimiter
    name_parts = full_name.split(delimiter)

    # Handle special characters if required
    if handle_special_characters:
        name_parts = [part.strip() for part in name_parts]

    # Handle prefix and suffix if required
    if prefix_handling and name_parts[0].lower() in ['dr', 'mr', 'ms', 'mrs']:
        name_parts = name_parts[1:]
