def digit_product_calculator(year, year_range=None, operation='product', output_format='integer', error_handling='strict'):
    """
    Calculate the product or sum of the digits of a given year or range of years.

    Parameters:
    - year (int): The year for which the product of digits is to be calculated.
    - year_range (list of int, optional): A range of years for which the product of digits is to be calculated.
    - operation (str, optional): The mathematical operation to perform on the digits ('product' or 'sum'). Defaults to 'product'.
    - output_format (str, optional): The format of the output ('integer', 'text', 'detailed'). Defaults to 'integer'.
    - error_handling (str, optional): Defines how to handle invalid inputs ('ignore', 'warn', 'strict'). Defaults to 'strict'.

    Returns:
    - The result of the operation in the specified format.
    """
    def calculate_digits_product(year):
        product = 1
        for digit in str(year):
            product *= int(digit)
        return product

    def calculate_digits_sum(year):
        return sum(int(digit) for digit in str(year))

    if not isinstance(year, int) or year <= 0:
        if error_handling == 'strict':
            raise ValueError("Year must be a positive integer.")
        elif error_handling == 'warn':
            print("Warning: Year must be a positive integer.")
            return None
        else:
            return None

    if operation not in ['product', 'sum']:
        if error_handling == 'strict':
            raise ValueError("Operation must be 'product' or 'sum'.")
        elif error_handling == 'warn':
            print("Warning: Operation must be 'product' or 'sum'.")
            return None
        else:
            return None

    result = calculate_digits_product(year) if operation == 'product' else calculate_digits_sum(year)

    if output_format == 'integer':
        return result
    elif output_format == 'text':
        return f"The result is {result}."
    elif output_format == 'detailed':
        return f"The {operation} of the digits of the year {year} is {result}."
    else:
        if error_handling == 'strict':
            raise ValueError("Invalid output format.")
        elif error_handling == 'warn':
            print("Warning: Invalid output format.")
            return None
        else:
            return None

