def sum_of_digits(number: str, ignore_non_digits: bool = True, output_format: str = 'integer', handle_decimals: bool = False, handle_negatives: bool = False, digit_range: list = None):
    # Validate the 'number' parameter
    if not isinstance(number, str):
        return {'error': 'Invalid input: number must be a string.'}

    # Validate the 'output_format' parameter
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output format. Choose from integer, text, or detailed.'}

    # Initialize the sum
    total_sum = 0
    detailed_breakdown = []

    # Define the range of digits to consider
    if digit_range is None:
        digit_range = list(range(10))  # Default to all digits 0-9

    # Iterate over each character in the number string
    for char in number:
        if char.isdigit() and int(char) in digit_range:
            total_sum += int(char)
            if output_format == 'detailed':
                detailed_breakdown.append(int(char))
        elif not ignore_non_digits and char not in ['-', '.']:
            return {'error': 'Invalid character found in number string.'}

    # Format the output based on the specified format
    if output_format == 'integer':
        return total_sum
    elif output_format == 'text':
        return f'The sum of digits is {total_sum}.'
    elif output_format == 'detailed':
        return {'sum': total_sum, 'breakdown': detailed_breakdown}

