def letter_counter(input: str, ignore_characters: list = None, ignore_position: list = None, output_format: str = 'integer', case_sensitive: bool = False, character_set: str = 'alphabetic', custom_character_set: list = None):
    # Validate parameters
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}
    if ignore_characters and not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'Invalid ignore_characters type. All items must be strings.'}
    if ignore_position and not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position value. Must be either "first" or "last".'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format. Must be "integer", "text", or "detailed".'}
    if character_set not in ['all', 'alphabetic', 'custom']:
        return {'error': 'Invalid character_set. Must be "all", "alphabetic", or "custom".'}
    if character_set == 'custom' and (not custom_character_set or not all(isinstance(char, str) for char in custom_character_set)):
        return {'error': 'Invalid custom_character_set. Must be a list of strings when character_set is "custom".'}

    # Prepare character set
    if character_set == 'alphabetic':
        valid_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ')
    elif character_set == 'custom':
        valid_chars = set(custom_character_set)
    else:  # 'all'
        valid_chars = set(chr(i) for i in range(256) if chr(i).isalpha())

    # Adjust for case sensitivity
    if not case_sensitive:
        input = input.lower()
        valid_chars = set(char.lower() for char in valid_chars)

    # Remove ignored characters
    if ignore_characters:
        input = ''.join(char for char in input if char not in ignore_characters)

    # Remove characters based on position
    if ignore_position:
        if 'first' in ignore_position and input:
            input = input[1:]
        if 'last' in ignore_position and input:
            input = input[:-1]

    # Count letters
    letter_count = 0
    detailed_count = {}
    for char in input:
        if char in valid_chars:
            letter_count += 1
            if output_format == 'detailed':
                if char in detailed_count:
                    detailed_count[char] += 1
                else:
                    detailed_count[char] = 1

    # Format output
    if output_format == 'integer':
        return letter_count
    elif output_format == 'text':
        return f'The string contains {letter_count} letters.'
    elif output_format == 'detailed':
        return detailed_count

