def extract_last_name(full_name: str, delimiter: str = ' ', name_format: str = 'first_last', case_sensitive: bool = False, cultural_format: str = 'western') -> str:
    """
    Extracts the last name from a full name string based on the specified parameters.

    :param full_name: The full name from which to extract the last name.
    :param delimiter: The delimiter used to separate names, default is a space.
    :param name_format: The expected format of the name. Defaults to 'first_last'.
    :param case_sensitive: Indicates if the extraction should be case sensitive. Defaults to false.
    :param cultural_format: Specifies the cultural naming convention to be used. Defaults to 'western'.
    :return: The extracted last name.
    """
    # Error handling for required parameter
    if not full_name:
        return "Error: 'full_name' parameter is required."

    # Split the full name based on the delimiter
    name_parts = full_name.split(delimiter)

    # Handle different name formats
    if name_format == 'first_last':
        if len(name_parts) < 2:
            return "Error: Name format 'first_last' requires at least two parts."
        last_name = name_parts[-1]
    elif name_format == 'first_middle_last':
        if len(name_parts) < 3:
            return "Error: Name format 'first_middle_last' requires at least three parts."
        last_name = name_parts[-1]
    elif name_format == 'multiple_last':
        if len(name_parts) < 2:
            return "Error: Name format 'multiple_last' requires at least two parts."
        last_name = delimiter.join(name_parts[1:])
    elif name_format == 'prefix_first_last':
        if len(name_parts) < 3:
            return "Error: Name format 'prefix_first_last' requires at least three parts."
        last_name = name_parts[-1]
    elif name_format == 'first_last_suffix':
        if len(name_parts) < 3:
            return "Error: Name format 'first_last_suffix' requires at least three parts."
        last_name = name_parts[-2]
    else:
        return "Error: Unsupported name format."

    # Handle case sensitivity
    if not case_sensitive:
        last_name = last_name.lower()

    # Handle cultural format (currently only 'western' is implemented)
    if cultural_format not in ['western', 'eastern', 'custom']:
        return "Error: Unsupported cultural format."

    return last_name

