def get_last_letter(input, output_format='character', case_sensitive=False, include_special_characters=True):
    """
    Extracts the last letter of each string in the input array based on the specified parameters.
    """
    if not isinstance(input, list) or len(input) < 1:
        return {'error': 'Input must be a non-empty list of strings.'}
    if output_format not in ['character', 'text', 'position', 'context']:
        return {'error': 'Invalid output format specified.'}

    results = []
    for string in input:
        if not isinstance(string, str):
            return {'error': 'All items in the input list must be strings.'}

        # Determine the last valid character
        last_char = None
        for char in reversed(string):
            if include_special_characters or char.isalnum():
                last_char = char
                break

        if last_char is None:
            results.append(None)
            continue

        # Handle case sensitivity
        if not case_sensitive:
            last_char = last_char.lower()

        # Determine the output format
        if output_format == 'character':
            results.append(last_char)
        elif output_format == 'text':
            results.append(f'The last letter is {last_char}.')
        elif output_format == 'position':
            position = string.rfind(last_char)
            results.append(position)
        elif output_format == 'context':
            context = string[max(0, string.rfind(last_char) - 1):string.rfind(last_char) + 2]
            results.append(context)

    return {'results': results}

