def char_to_binary(input: str, output_format: str = 'binary_string', encoding: str = 'UTF-8', bit_length: int = 8, case_sensitive: bool = True, ignore_non_alphabetic: bool = False):
    # Validate input
    if not input:
        return {'error': 'Input must be at least one character long.'}
    if output_format not in ['binary_string', 'binary_list', 'binary_dict']:
        return {'error': 'Invalid output format specified.'}
    if encoding not in ['ASCII', 'UTF-8']:
        return {'error': 'Invalid encoding specified.'}
    if bit_length not in [8, 16, 32]:
        return {'error': 'Invalid bit length specified.'}

    # Prepare input based on case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Filter non-alphabetic characters if needed
    if ignore_non_alphabetic:
        input = ''.join(filter(str.isalpha, input))

    # Convert characters to binary
    binary_codes = []
    for char in input:
        if encoding == 'ASCII':
            binary_code = format(ord(char), f'0{bit_length}b')
        else:  # UTF-8
            binary_code = ''.join(format(byte, f'0{bit_length}b') for byte in char.encode('utf-8'))
        binary_codes.append(binary_code)

    # Format output
    if output_format == 'binary_string':
        return ''.join(binary_codes)
    elif output_format == 'binary_list':
        return binary_codes
    elif output_format == 'binary_dict':
        return {char: code for char, code in zip(input, binary_codes)}

    return {'error': 'An unknown error occurred.'}

