def extract_last_character_v2(input, output_format='character', handle_empty='ignore', default_value=''):
    """
    Extracts the last character from a given string or array of strings.

    Parameters:
    input (str or list of str): The string or array of strings from which the last character(s) will be extracted.
    output_format (str): The format of the output. Options are 'character', 'ascii', 'unicode', 'hex'.
    handle_empty (str): Specifies how to handle empty strings. Options are 'ignore', 'error', 'default'.
    default_value (str): The default value to return if the input is an empty string and 'handle_empty' is set to 'default'.

    Returns:
    str or list of str: The last character(s) in the specified format.
    """
    def format_character(char, format_type):
        if format_type == 'ascii':
            return str(ord(char))
        elif format_type == 'unicode':
            return f'U+{ord(char):04X}'
        elif format_type == 'hex':
            return f'0x{ord(char):02X}'
        return char

    if isinstance(input, str):
        if not input:
            if handle_empty == 'error':
                raise ValueError('Input string is empty.')
            elif handle_empty == 'default':
                return default_value
            return ''
        last_char = input[-1]
        return format_character(last_char, output_format)

    elif isinstance(input, list):
        results = []
        for item in input:
            if not item:
                if handle_empty == 'error':
                    raise ValueError('One of the input strings is empty.')
                elif handle_empty == 'default':
                    results.append(default_value)
                else:
                    results.append('')
            else:
                last_char = item[-1]
                results.append(format_character(last_char, output_format))
        return results
    else:
        raise TypeError('Input must be a string or an array of strings.')

