def last_character_extractor_v2(input: str, handle_empty: bool = False, output_format: str = 'character', encoding: str = 'utf-8', case_sensitive: bool = True, error_handling: str = 'strict'):
    """
    Extracts the last character from the input string based on specified parameters.
    """
    # Error handling for empty input
    if not input:
        if handle_empty:
            return {'error': 'Input string is empty.'}
        else:
            return {'result': None}

    # Attempt to encode the string
    try:
        encoded_input = input.encode(encoding)
    except UnicodeEncodeError as e:
        if error_handling == 'ignore':
            return {'result': None}
        elif error_handling == 'warn':
            return {'warning': str(e), 'result': None}
        else:  # strict
            raise e

    # Extract the last character
    last_char = input[-1]

    # Handle case sensitivity
    if not case_sensitive:
        last_char = last_char.lower()

    # Format the output
    if output_format == 'unicode':
        result = ord(last_char)
    elif output_format == 'ascii':
        result = ord(last_char) if ord(last_char) < 128 else None
    elif output_format == 'hex':
        result = hex(ord(last_char))
    else:  # default to 'character'
        result = last_char

    return {'result': result}

