    if not isinstance(strings, list) or len(strings) < 2:
        return 'Error: At least two strings are required.'

    # Process each string based on options
    processed_strings = []
    for s in strings:
        if s is None and ignoreNull:
            continue
        if trimWhitespace and isinstance(s, str):
            s = s.strip()
        if caseTransformation == 'uppercase':
            s = s.upper()
        elif caseTransformation == 'lowercase':
            s = s.lower()
        elif caseTransformation == 'capitalize':
            s = s.capitalize()
        processed_strings.append(s)

    # Concatenate strings with delimiter
    result = delimiter.join(processed_strings)

