def last_digit_extractor(number: str, ignore_sign: bool = True, output_format: str = 'string', numeral_system: str = 'decimal', digit_position: int = 1, handle_non_numeric: str = 'ignore'):
    """
    Extracts a specified digit from a given number based on the provided parameters.
    """
    # Validate numeral system
    if numeral_system not in ['decimal', 'binary', 'hexadecimal']:
        return {'error': 'Invalid numeral system specified.'}

    # Handle non-numeric characters
    if handle_non_numeric == 'error' and not number.isdigit():
        return {'error': 'Non-numeric characters present in input.'}

    # Remove non-numeric characters if needed
    if handle_non_numeric == 'ignore':
        number = ''.join(filter(str.isdigit, number))

    # Handle sign
    if ignore_sign:
        number = number.lstrip('-')

    # Convert number based on numeral system
    try:
        if numeral_system == 'binary':
            number = str(int(number, 2))
        elif numeral_system == 'hexadecimal':
            number = str(int(number, 16))
    except ValueError:
        return {'error': 'Invalid number for the specified numeral system.'}

    # Check if digit position is valid
    if digit_position > len(number) or digit_position < 1:
        return {'error': 'Digit position out of range.'}

    # Extract the digit
    digit = number[-digit_position]

    # Return in the specified format
    if output_format == 'integer':
        return {'result': int(digit)}
    else:
        return {'result': digit}

