def digit_product_calculator(year, output_format='integer', verbosity='low', include_zero_handling=False):
    # Error handling for 'year' parameter
    if not isinstance(year, int) or year < 1 or year > 9999:
        return {'error': 'Year must be an integer between 1 and 9999.'}

    # Error handling for 'output_format' parameter
    if output_format not in ['integer', 'text', 'json']:
        return {'error': 'Invalid output format. Choose from integer, text, or json.'}

    # Error handling for 'verbosity' parameter
    if verbosity not in ['low', 'medium', 'high']:
        return {'error': 'Invalid verbosity level. Choose from low, medium, or high.'}

    # Calculate the product of the digits
    digits = [int(d) for d in str(year)]
    if include_zero_handling:
        digits = [d for d in digits if d != 0]
    product = 1
    for digit in digits:
        product *= digit

    # Prepare the output based on verbosity
    if verbosity == 'low':
        result = product
    elif verbosity == 'medium':
        result = f"Product of digits {digits} is {product}."
    else:  # verbosity == 'high'
        result = f"Calculating the product of the digits of {year}: {' * '.join(map(str, digits))} = {product}."

    # Format the output
    if output_format == 'integer':
        return product
    elif output_format == 'text':
        return str(result)
    else:  # output_format == 'json'
        return {'year': year, 'product': product, 'details': result}

