def character_counter(input, characters, case_sensitive=False, ignore_whitespace=False, output_format='integer'):
    # Validate input parameters
    if not isinstance(input, list) or not all(isinstance(s, str) for s in input):
        raise ValueError('Input must be a list of strings.')
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        raise ValueError('Characters must be a list of single-character strings.')
    if not isinstance(case_sensitive, bool):
        raise ValueError('Case_sensitive must be a boolean.')
    if not isinstance(ignore_whitespace, bool):
        raise ValueError('Ignore_whitespace must be a boolean.')
    if output_format not in ['integer', 'text', 'detailed']:
        raise ValueError("Output_format must be 'integer', 'text', or 'detailed'.")

    # Prepare strings based on options
    if not case_sensitive:
        input = [s.lower() for s in input]
        characters = [c.lower() for c in characters]
    if ignore_whitespace:
        input = [''.join(s.split()) for s in input]

    # Count occurrences
    counts = {char: 0 for char in characters}
    for string in input:
        for char in characters:
            counts[char] += string.count(char)

    # Format output
    if output_format == 'integer':
        return sum(counts.values())
    elif output_format == 'text':
        return ', '.join(f"'{char}': {count}" for char, count in counts.items())
    elif output_format == 'detailed':
        return counts

