def enhanced_sum_of_digits(number, output_format='integer', include_negative_sign=False, precision=0):
    """
    Calculate the sum of the digits of a given number with customizable output.
    :param number: The number whose digits will be summed.
    :param output_format: The format of the output.
    :param include_negative_sign: Whether to include the negative sign in the sum.
    :param precision: Number of decimal places to consider for floats.
    :return: Sum of digits in the specified format.
    """
    try:
        # Convert number to string and handle precision for floats
        if isinstance(number, float):
            number_str = f"{number:.{precision}f}"
        else:
            number_str = str(number)

        # Handle negative sign
        if not include_negative_sign and number_str.startswith('-'):
            number_str = number_str[1:]

        # Remove decimal point
        number_str = number_str.replace('.', '')

        # Calculate sum of digits
        digit_sum = sum(int(digit) for digit in number_str if digit.isdigit())

        # Format output based on output_format
        if output_format == 'integer':
            return digit_sum
        elif output_format == 'text':
            return str(digit_sum)
        elif output_format == 'detailed_text':
            return f"The sum of the digits of {number} is {digit_sum}."
        elif output_format == 'json':
            return {'sum': digit_sum}
        else:
            raise ValueError("Invalid output_format specified.")
    except Exception as e:
        return f"Error: {str(e)}"

