    """
    try:
        # Strip whitespace if required
        if strip_whitespace:
            number = number.strip()

        # Handle sign ignoring
        if ignore_sign and number.startswith('-'):
            number = number[1:]

        # Handle decimals
        if '.' in number:
            if handle_decimals == 'truncate':
                number = number.split('.')[0]
            elif handle_decimals == 'round':
                number = str(round(float(number)))
            elif handle_decimals == 'ignore':
                pass  # Treat as string

        # Extract the last character
        last_char = number[-1]

        # Determine output format
        if output_format == 'integer':
            return int(last_char)
        elif output_format == 'string':
            return last_char
        elif output_format == 'character':
            return last_char
        else:
            raise ValueError("Invalid output format specified.")

    except (ValueError, IndexError) as e:
        return f"Error: {str(e)}"

