    # Convert numbers to strings if convert_numbers is True
    if convert_numbers:
        values = [str(value) if isinstance(value, (int, float)) else value for value in values]

    # Concatenate values with the specified separator
    concatenated_result = separator.join(map(str, values))

    # Add prefix and suffix
    final_result = f'{prefix}{concatenated_result}{suffix}'

    # Format output based on output_format
    if output_format == 'json':
        import json
        return json.dumps({'result': final_result})
    elif output_format == 'xml':
        return f'<result>{final_result}</result>'
