def extract_first_name(full_name, delimiter=' ', additional_delimiters=[], ignore_case=True, handle_special_characters=True, name_order='first_last', handle_titles=False):
    """
    Extracts the first name from a given full name string based on specified parameters.
    """
    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name provided. It must be a non-empty string.'}

    # Normalize case if ignore_case is True
    if ignore_case:
        full_name = full_name.lower()

    # Handle titles if handle_titles is True
    if handle_titles:
        titles = ['dr.', 'mr.', 'ms.', 'mrs.', 'miss', 'prof.']
        for title in titles:
            if full_name.startswith(title):
                full_name = full_name[len(title):].strip()

    # Combine delimiters
    delimiters = [delimiter] + additional_delimiters

    # Split the full name using the delimiters
    import re
    regex_pattern = '|'.join(map(re.escape, delimiters))
    name_parts = re.split(regex_pattern, full_name)

    # Handle special characters if handle_special_characters is True
    if handle_special_characters:
        name_parts = [re.sub(r'[^a-zA-Z]', '', part) for part in name_parts]

    # Determine the first name based on name order
    if name_order == 'first_last':
        first_name = name_parts[0]
    elif name_order == 'last_first':
        first_name = name_parts[-1]
    else:
        return {'error': 'Invalid name_order provided. It must be either "first_last" or "last_first".'}

    # Return the extracted first name
    return {'first_name': first_name.capitalize() if ignore_case else first_name}

