def extract_last_name(full_name: str, name_format: str = 'standard', ignore_titles: bool = True, handle_suffixes: bool = False, name_delimiter: str = ' ') -> str:
    # Error handling for required parameter
    if not full_name:
        raise ValueError('The full_name parameter is required.')

    # Split the full name using the specified delimiter
    name_parts = full_name.split(name_delimiter)

    # Handle titles if ignore_titles is True
    if ignore_titles:
        titles = {'Dr.', 'Mr.', 'Ms.', 'Mrs.', 'Miss'}
        name_parts = [part for part in name_parts if part not in titles]

    # Handle suffixes if handle_suffixes is True
    if handle_suffixes:
        suffixes = {'Jr.', 'Sr.', 'III', 'IV'}
        name_parts = [part for part in name_parts if part not in suffixes]

    # Determine last name based on name_format
    if name_format == 'standard':
        last_name = name_parts[-1]
    elif name_format == 'hyphenated':
        last_name = name_parts[-1] if '-' not in name_parts[-1] else name_parts[-1].split('-')[-1]
    elif name_format == 'multiple_last_names':
        last_name = name_parts[-1] if len(name_parts) > 1 else name_parts[0]
    else:
        raise ValueError('Invalid name_format specified.')

    return last_name

