def digit_product_calculator_v2(year: int, output_format: str = 'integer', handle_zero: bool = False, include_steps: bool = False):
    # Validate the 'year' parameter
    if not (1000 <= year <= 9999):
        return {'error': 'Year must be a four-digit integer between 1000 and 9999.'}

    # Validate the 'output_format' parameter
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': "Output format must be one of ['integer', 'text', 'detailed']."}

    # Extract digits from the year
    digits = [int(d) for d in str(year)]

    # Calculate the product of the digits
    product = 1
    for digit in digits:
        product *= digit

    # Handle zero digits if specified
    if handle_zero and 0 in digits:
        return {'message': 'Year contains zero, special handling applied.'}

    # Prepare the output based on the 'output_format'
    if output_format == 'integer':
        return product
    elif output_format == 'text':
        return f'The product of the digits of the year {year} is {product}.'
    elif output_format == 'detailed':
        steps = ' * '.join(map(str, digits))
        detailed_output = f'The product of the digits of the year {year} is calculated as: {steps} = {product}.'
        if include_steps:
            return {'product': product, 'steps': steps, 'detailed_output': detailed_output}
        else:
            return {'product': product, 'detailed_output': detailed_output}

