def extract_last_name(full_name, delimiter=' ', cultural_convention='western', custom_delimiter=None, include_middle_names=False, handle_suffixes=True, handle_prefixes=False):
    # Error handling for required parameter
    if not isinstance(full_name, str) or ' ' not in full_name:
        return {'error': 'Invalid full_name. It must be a string containing at least one space.'}

    # Determine the delimiter to use
    if cultural_convention == 'custom' and custom_delimiter:
        delimiter = custom_delimiter

    # Split the full name based on the delimiter
    name_parts = full_name.split(delimiter)

    # Handle prefixes if required
    if handle_prefixes:
        prefixes = ['Dr.', 'Mr.', 'Ms.', 'Mrs.']
        name_parts = [part for part in name_parts if part not in prefixes]

    # Handle suffixes if required
    if handle_suffixes:
        suffixes = ['Jr.', 'Sr.', 'III', 'IV']
        name_parts = [part for part in name_parts if part not in suffixes]

    # Extract last name based on cultural convention
    if cultural_convention == 'western':
        last_name = name_parts[-1]
    elif cultural_convention == 'eastern':
        last_name = name_parts[0]
    elif cultural_convention == 'latin_american':
        last_name = name_parts[-2] if len(name_parts) > 1 else name_parts[-1]
    elif cultural_convention == 'arabic':
        last_name = name_parts[-1]
    else:
        return {'error': 'Invalid cultural_convention.'}

    # Include middle names if required
    if include_middle_names and len(name_parts) > 2:
        middle_names = name_parts[1:-1]
        last_name = ' '.join(middle_names + [last_name])

    return {'last_name': last_name}

