def char_to_binary(characters, bit_length=8, output_format='string', encoding='ASCII', delimiter=''):
    # Validate parameters
    if encoding not in ['ASCII', 'UTF-8', 'UTF-16']:
        return {'error': 'Unsupported encoding specified.'}
    if output_format not in ['string', 'array', 'hex']:
        return {'error': 'Invalid output format specified.'}
    if bit_length <= 0:
        return {'error': 'Bit length must be a positive integer.'}

    # Convert characters to binary
    try:
        binary_list = []
        for char in characters:
            if encoding == 'ASCII':
                binary_value = format(ord(char), f'0{bit_length}b')
            elif encoding == 'UTF-8':
                binary_value = ''.join(format(byte, f'0{bit_length}b') for byte in char.encode('utf-8'))
            elif encoding == 'UTF-16':
                binary_value = ''.join(format(byte, f'0{bit_length}b') for byte in char.encode('utf-16')[2:])
            binary_list.append(binary_value)

        # Format output
        if output_format == 'string':
            return delimiter.join(binary_list)
        elif output_format == 'array':
            return binary_list
        elif output_format == 'hex':
            return ''.join(format(int(b, 2), 'x') for b in binary_list)
    except Exception as e:
        return {'error': str(e)}

