def unique_letter_counter(input: str, case_sensitive: bool = False, exclude_characters: list = [], exclude_character_classes: list = [], alphabetic_only: bool = True, character_set: str = 'Latin') -> int:
    # Validate input type
    if not isinstance(input, str):
        raise ValueError('Input must be a string.')
    if not isinstance(case_sensitive, bool):
        raise ValueError('case_sensitive must be a boolean.')
    if not isinstance(exclude_characters, list):
        raise ValueError('exclude_characters must be a list.')
    if not isinstance(exclude_character_classes, list):
        raise ValueError('exclude_character_classes must be a list.')
    if not isinstance(alphabetic_only, bool):
        raise ValueError('alphabetic_only must be a boolean.')
    if not isinstance(character_set, str):
        raise ValueError('character_set must be a string.')

    # Normalize the input based on case sensitivity
    if not case_sensitive:
        input = input.lower()

    # Define character classes to exclude
    import string
    exclude_set = set(exclude_characters)
    if 'digits' in exclude_character_classes:
        exclude_set.update(string.digits)
    if 'punctuation' in exclude_character_classes:
        exclude_set.update(string.punctuation)

    # Filter characters based on exclusions and alphabetic_only
    unique_letters = set()
    for char in input:
        if char in exclude_set:
            continue
        if alphabetic_only and not char.isalpha():
            continue
        if character_set == 'Latin' and not (char.isascii() and char.isalpha()):
            continue
        # Add character to the set of unique letters
        unique_letters.add(char)

    return len(unique_letters)

