def first_letter_extractor(input, trim_whitespace=True, case_sensitive=True, extract_mode='first_letter', include_non_alpha=False, output_format='string'):
    # Error handling for required parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input: input must be a string.'}

    # Validate parameter types
    if not isinstance(trim_whitespace, bool):
        return {'error': 'Invalid parameter: trim_whitespace must be a boolean.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid parameter: case_sensitive must be a boolean.'}
    if extract_mode not in ['first_letter', 'each_word']:
        return {'error': "Invalid parameter: extract_mode must be 'first_letter' or 'each_word'."}
    if not isinstance(include_non_alpha, bool):
        return {'error': 'Invalid parameter: include_non_alpha must be a boolean.'}
    if output_format not in ['string', 'list']:
        return {'error': "Invalid parameter: output_format must be 'string' or 'list'."}

    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Extract first letter(s) based on mode
    if extract_mode == 'first_letter':
        first_letter = input[0] if input else ''
        if not include_non_alpha and not first_letter.isalpha():
            first_letter = ''
    else:  # each_word
        words = input.split()
        first_letters = [word[0] for word in words if word]
        if not include_non_alpha:
            first_letters = [ch for ch in first_letters if ch.isalpha()]

    # Maintain case sensitivity
    if not case_sensitive:
        if extract_mode == 'first_letter':
            first_letter = first_letter.lower()
        else:
            first_letters = [ch.lower() for ch in first_letters]

    # Format output
    if output_format == 'string':
        if extract_mode == 'first_letter':
            return first_letter
        else:
            return ''.join(first_letters)
    else:  # list
        if extract_mode == 'first_letter':
            return [first_letter] if first_letter else []
        else:
            return first_letters

