def letter_counter(input, ignore_characters=None, ignore_position=None, output_format='integer', case_sensitive=False, count_type='all'):
    # Validate input parameter
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Default values
    if ignore_characters is None:
        ignore_characters = []
    if ignore_position is None:
        ignore_position = []

    # Validate other parameters
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) for c in ignore_characters):
        return {'error': 'Invalid ignore_characters type. Must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Invalid ignore_position type. Must be a list containing "first" or "last".'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid output_format. Must be "integer", "text", or "detailed".'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid case_sensitive type. Must be a boolean.'}
    if count_type not in ['all', 'vowels', 'consonants']:
        return {'error': 'Invalid count_type. Must be "all", "vowels", or "consonants".'}

    # Prepare the input string
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [c.lower() for c in ignore_characters]

    # Define vowels and consonants
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Filter out ignored characters
    filtered_input = ''.join([char for char in input if char not in ignore_characters])

    # Filter out ignored positions
    if 'first' in ignore_position and filtered_input:
        filtered_input = filtered_input[1:]
    if 'last' in ignore_position and filtered_input:
        filtered_input = filtered_input[:-1]

    # Count letters based on count_type
    if count_type == 'vowels':
        count = sum(1 for char in filtered_input if char in vowels)
    elif count_type == 'consonants':
        count = sum(1 for char in filtered_input if char in consonants)
    else:
        count = sum(1 for char in filtered_input if char.isalpha())

    # Format the output
    if output_format == 'integer':
        return count
    elif output_format == 'text':
        return f'The count is {count}.'
    elif output_format == 'detailed':
        vowel_count = sum(1 for char in filtered_input if char in vowels)
        consonant_count = sum(1 for char in filtered_input if char in consonants)
        return {
            'total': count,
            'vowels': vowel_count,
            'consonants': consonant_count
        }

