def name_length_counter(name, ignore_characters=[], ignore_position=[], case_sensitive=False, count_type='all'):
    # Validate input parameters
    if not isinstance(name, str):
        return {'error': 'Invalid input: name must be a string.'}
    if not isinstance(ignore_characters, list) or not all(isinstance(c, str) for c in ignore_characters):
        return {'error': 'Invalid input: ignore_characters must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Invalid input: ignore_position must be a list containing "first" or "last".'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid input: case_sensitive must be a boolean.'}
    if count_type not in ['all', 'vowels', 'consonants']:
        return {'error': 'Invalid input: count_type must be "all", "vowels", or "consonants".'}

    # Prepare the name for processing
    if not case_sensitive:
        name = name.lower()
        ignore_characters = [c.lower() for c in ignore_characters]

    # Define vowels and consonants
    vowels = 'aeiou'
    consonants = 'bcdfghjklmnpqrstvwxyz'

    # Apply ignore_position
    if 'first' in ignore_position and len(name) > 0:
        name = name[1:]
    if 'last' in ignore_position and len(name) > 0:
        name = name[:-1]

    # Count characters based on count_type
    count = 0
    for char in name:
        if char in ignore_characters:
            continue
        if count_type == 'vowels' and char not in vowels:
            continue
        if count_type == 'consonants' and char not in consonants:
            continue
        count += 1

    return {'count': count}

