def extract_last_name(full_name, delimiter=[' '], handle_single_name=True, output_format='string', include_middle_name=False, handle_prefixes=True, handle_suffixes=False):
    # Error handling for required parameter
    if not isinstance(full_name, str) or not full_name.strip():
        return {'error': 'Invalid full_name. It must be a non-empty string.'}

    # Split the full name using the provided delimiters
    import re
    delimiters_regex = '|'.join(map(re.escape, delimiter))
    name_parts = re.split(delimiters_regex, full_name)

    # Remove empty strings from name_parts
    name_parts = [part for part in name_parts if part]

    # Handle single name case
    if len(name_parts) == 1:
        if handle_single_name:
            last_name = name_parts[0]
        else:
            return {'error': 'Only one name provided and handle_single_name is False.'}
    else:
        # Handle prefixes
        if handle_prefixes:
            prefixes = {'Dr.', 'Mr.', 'Ms.', 'Mrs.', 'Miss'}
            name_parts = [part for part in name_parts if part not in prefixes]

        # Handle suffixes
        if not handle_suffixes:
            suffixes = {'Jr.', 'Sr.', 'III', 'IV'}
            name_parts = [part for part in name_parts if part not in suffixes]

        # Determine the last name
        if include_middle_name and len(name_parts) > 2:
            last_name = ' '.join(name_parts[1:])
        else:
            last_name = name_parts[-1]

    # Format the output
    if output_format == 'string':
        return last_name
    elif output_format == 'array':
        return [last_name]
    elif output_format == 'json':
        return {'last_name': last_name}
    elif output_format == 'xml':
        return f'<lastName>{last_name}</lastName>'
    else:
        return {'error': 'Invalid output_format specified.'}

