def legislative_sponsor_finder(resolution_title: str, sponsor_name: str = '', year: int = None, output_format: str = 'list', sponsor_party: str = '', resolution_status: str = '') -> dict:
    """
    Find sponsors and co-sponsors of legislative resolutions based on various filters.

    Parameters:
    - resolution_title (str): The title or keywords of the resolution to search for.
    - sponsor_name (str, optional): The name of a known sponsor to narrow down the search.
    - year (int, optional): The year the resolution was introduced.
    - output_format (str): The format of the output ('list', 'detailed', 'summary').
    - sponsor_party (str, optional): The political party of the sponsor to refine the search.
    - resolution_status (str, optional): The current status of the resolution ('introduced', 'passed', 'failed').

    Returns:
    - dict: A dictionary containing the search results or an error message.
    """
    # Simulated database of resolutions
    resolutions_db = [
        {
            'title': 'Resolution to Reopen Trade with Vietnam',
            'sponsors': ['John Kerry', 'John McCain'],
            'year': 1994,
            'party': 'Republican',
            'status': 'passed'
        },
        # Additional entries could be added here for a more comprehensive simulation
    ]

    # Validate required parameter
    if not resolution_title:
        return {'error': 'The resolution_title parameter is required.'}

    # Validate output_format
    if output_format not in ['list', 'detailed', 'summary']:
        return {'error': 'Invalid output_format. Choose from list, detailed, or summary.'}

    # Search for resolutions
    results = []
    for resolution in resolutions_db:
        if resolution_title.lower() in resolution['title'].lower():
            if sponsor_name and sponsor_name.lower() not in [s.lower() for s in resolution['sponsors']]:
                continue
            if year and resolution['year'] != year:
                continue
            if sponsor_party and resolution['party'].lower() != sponsor_party.lower():
                continue
            if resolution_status and resolution['status'].lower() != resolution_status.lower():
                continue
            results.append(resolution)

    # Format results based on output_format
    if not results:
        return {'error': 'No resolutions found matching the criteria.'}

    if output_format == 'list':
        return {'sponsors': [sponsor for res in results for sponsor in res['sponsors']]}
    elif output_format == 'detailed':
        return {'detailed_results': results}
    elif output_format == 'summary':
        return {'summary': [{'title': res['title'], 'sponsors': res['sponsors']} for res in results]}

    return {'error': 'Unexpected error occurred.'}

