    if not full_name:
        return {'error': 'full_name is required'}

    # Validate delimiter
    valid_delimiters = ['space', 'hyphen', 'comma', 'semicolon', 'both', 'custom']
    if delimiter not in valid_delimiters:
        return {'error': 'Invalid delimiter specified'}

    # Determine actual delimiter
    if delimiter == 'space':
        actual_delimiter = ' '
    elif delimiter == 'hyphen':
        actual_delimiter = '-'
    elif delimiter == 'comma':
        actual_delimiter = ','
    elif delimiter == 'semicolon':
        actual_delimiter = ';'
    elif delimiter == 'both':
        actual_delimiter = ' |-|,|;'
    elif delimiter == 'custom' and custom_delimiter:
        actual_delimiter = custom_delimiter
    else:
        return {'error': 'Custom delimiter must be provided when delimiter is set to custom'}

    # Handle case sensitivity
    if not case_sensitive:
        full_name = full_name.lower()

    # Handle prefixes and suffixes
    prefixes = ['mr.', 'mrs.', 'dr.', 'ms.'] if prefix_handling else []
    suffixes = ['jr.', 'sr.', 'ii', 'iii'] if suffix_handling else []

    # Split the full name
    name_parts = full_name.split(actual_delimiter)

    # Remove prefixes
    if prefix_handling:
        name_parts = [part for part in name_parts if part not in prefixes]

    # Remove suffixes
    if suffix_handling:
        name_parts = [part for part in name_parts if part not in suffixes]

    # Extract first name(s)
    if multiple_first_names:
        first_names = ' '.join(name_parts[:2])  # Assuming two first names
