def ascii_converter_plus(characters, encoding='ASCII', extended_ascii=False):
    # Validate input parameters
    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        return {'error': 'Invalid input: characters must be a list of single-character strings.'}
    if encoding not in ['ASCII', 'Unicode']:
        return {'error': "Invalid encoding type: must be 'ASCII' or 'Unicode'."}

    # Initialize result list
    result = []

    # Process each character
    for char in characters:
        try:
            if encoding == 'ASCII':
                # Handle extended ASCII if flag is set
                if extended_ascii and ord(char) > 127:
                    result.append({'character': char, 'code': ord(char)})
                elif ord(char) <= 127:
                    result.append({'character': char, 'code': ord(char)})
                else:
                    result.append({'character': char, 'error': 'Character not in ASCII range'})
            elif encoding == 'Unicode':
                result.append({'character': char, 'code': ord(char)})
        except Exception as e:
            result.append({'character': char, 'error': str(e)})

    return {'result': result}

