    import string

    # Error handling for input type
    if not isinstance(input, str):
        return 'Error: Input must be a string.'

    # Trim whitespace if required
    if trim_whitespace:
        input = input.strip()

    # Define character filters
    if character_type == 'letter':
        char_filter = str.isalpha
    elif character_type == 'digit':
        char_filter = str.isdigit
    else:
        char_filter = lambda x: True  # 'any' type

    # Process the string from end to start
    for char in reversed(input):
        if ignore_punctuation and char in string.punctuation:
            continue
        if char_filter(char):
            if output_format == 'ascii':
                return str(ord(char))
            elif output_format == 'unicode':
                return f'U+{ord(char):04X}'
            else:
                return char

    return 'Error: No valid character found.'

