def year_calculator(base_year, operation_sequence, calendar_system='gregorian', output_format='integer'):
    # Validate base_year
    if not isinstance(base_year, int):
        return {'error': 'Invalid base_year: must be an integer.'}

    # Validate operation_sequence
    if not isinstance(operation_sequence, list) or not all(isinstance(op, dict) for op in operation_sequence):
        return {'error': 'Invalid operation_sequence: must be a list of operations.'}

    # Validate each operation in the sequence
    for op in operation_sequence:
        if 'operation' not in op or 'value' not in op:
            return {'error': 'Each operation must include an operation and a value.'}
        if op['operation'] not in ['add', 'subtract']:
            return {'error': f"Invalid operation: {op['operation']} is not supported."}
        if not isinstance(op['value'], int):
            return {'error': 'Operation value must be an integer.'}

    # Validate calendar_system
    if calendar_system not in ['gregorian', 'julian']:
        return {'error': f"Invalid calendar_system: {calendar_system} is not supported."}

    # Validate output_format
    if output_format not in ['integer', 'string', 'detailed']:
        return {'error': f"Invalid output_format: {output_format} is not supported."}

    # Perform operations
    result_year = base_year
    for op in operation_sequence:
        if op['operation'] == 'add':
            result_year += op['value']
        elif op['operation'] == 'subtract':
            result_year -= op['value']

    # Format output
    if output_format == 'integer':
        return result_year
    elif output_format == 'string':
        return str(result_year)
    elif output_format == 'detailed':
        return {
            'year': result_year,
            'calendar_system': calendar_system,
            'operations': operation_sequence
        }

