def string_length_calculator(input, ignore_characters=[], ignore_position=[], case_sensitive=False, ignore_whitespace=True, output_format='integer'):
    # Validate input types
    if not isinstance(input, str):
        return {'error': 'Input must be a string.'}
    if not isinstance(ignore_characters, list) or not all(isinstance(char, str) for char in ignore_characters):
        return {'error': 'Ignore characters must be a list of strings.'}
    if not isinstance(ignore_position, list) or not all(pos in ['first', 'last'] for pos in ignore_position):
        return {'error': 'Ignore position must be a list containing "first" or "last".'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Case sensitive must be a boolean.'}
    if not isinstance(ignore_whitespace, bool):
        return {'error': 'Ignore whitespace must be a boolean.'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Output format must be "integer", "text", or "detailed".'}

    # Prepare the string for processing
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Remove ignored characters
    filtered_input = ''.join(char for char in input if char not in ignore_characters)

    # Remove whitespace if needed
    if ignore_whitespace:
        filtered_input = filtered_input.replace(' ', '')

    # Remove characters based on position
    if 'first' in ignore_position and filtered_input:
        filtered_input = filtered_input[1:]
    if 'last' in ignore_position and filtered_input:
        filtered_input = filtered_input[:-1]

    # Calculate the number of letters
    letter_count = sum(char.isalpha() for char in filtered_input)

    # Format the output
    if output_format == 'integer':
        return letter_count
    elif output_format == 'text':
        return f'The total number of letters is {letter_count}.'
    elif output_format == 'detailed':
        return {
            'original': input,
            'filtered': filtered_input,
            'letter_count': letter_count,
            'details': {
                'ignore_characters': ignore_characters,
                'ignore_position': ignore_position,
                'case_sensitive': case_sensitive,
                'ignore_whitespace': ignore_whitespace
            }
        }

