def string_length_counter(input, ignore_characters=[], ignore_patterns=[], ignore_position=[], case_sensitive=False, output_format='integer'):
    import re

    # Error handling for input type
    if not isinstance(input, str):
        return {'error': 'Invalid input type. Input must be a string.'}

    # Apply case sensitivity
    if not case_sensitive:
        input = input.lower()
        ignore_characters = [char.lower() for char in ignore_characters]

    # Remove ignored characters
    for char in ignore_characters:
        input = input.replace(char, '')

    # Remove ignored patterns
    for pattern in ignore_patterns:
        input = re.sub(pattern, '', input)

    # Remove ignored positions
    if 'first' in ignore_position and len(input) > 0:
        input = input[1:]
    if 'last' in ignore_position and len(input) > 0:
        input = input[:-1]
    if 'middle' in ignore_position and len(input) > 2:
        input = input[0] + input[-1]

    # Count letters
    letter_count = sum(1 for char in input if char.isalpha())

    # Format output
    if output_format == 'integer':
        return letter_count
    elif output_format == 'text':
        return f'The number of letters is {letter_count}.'
    elif output_format == 'detailed':
        from collections import Counter
        count_details = Counter(input)
        return dict(count_details)
    else:
        return {'error': 'Invalid output format specified.'}

