def digit_extractor(number: str, position: int = None, range: dict = None, multiple_positions: list = None, output_format: str = 'integer'):
    """
    Extracts specific digits or sequences of digits from a numerical string.
    """
    # Error handling for invalid number input
    if not isinstance(number, str) or not number.replace('-', '').replace('.', '').isdigit():
        return {'error': 'Invalid number format. Please provide a valid numerical string.'}

    # Convert number to a clean string without negative sign for indexing
    clean_number = number.lstrip('-')

    # Determine the extraction method
    if multiple_positions:
        # Extract digits at multiple specified positions
        try:
            extracted_digits = [clean_number[pos - 1] for pos in multiple_positions]
        except IndexError:
            return {'error': 'One or more positions are out of bounds.'}
    elif range:
        # Extract a range of digits
        try:
            start, end = range['start'], range['end']
            extracted_digits = clean_number[start - 1:end]
        except IndexError:
            return {'error': 'Range is out of bounds.'}
    elif position:
        # Extract a single digit at the specified position
        try:
            extracted_digits = clean_number[position - 1]
        except IndexError:
            return {'error': 'Position is out of bounds.'}
    else:
        return {'error': 'No valid extraction method provided.'}

