def advanced_digit_extractor(number: str, positions: list, numeral_system: str = 'decimal', error_handling: str = 'raise', default_value: str = '') -> str:
    """
    Extracts digits from a numerical string based on specified positions.

    :param number: The numerical string from which the digits will be extracted.
    :param positions: An array of 1-based index positions specifying which digits to extract.
    :param numeral_system: The numeral system of the input string, defaulting to 'decimal'.
    :param error_handling: Defines how to handle errors such as invalid positions or non-numeric characters.
    :param default_value: The default value to use when an error is encountered and 'default' error handling is selected.
    :return: A string of extracted digits.
    """
    # Validate numeral system
    if numeral_system not in ['decimal', 'binary', 'hexadecimal']:
        raise ValueError("Invalid numeral system specified.")

    # Convert number to the appropriate numeral system if necessary
    if numeral_system == 'binary':
        try:
            number = bin(int(number, 2))[2:]
        except ValueError:
            if error_handling == 'raise':
                raise ValueError("Invalid binary number.")
            elif error_handling == 'default':
                return default_value
    elif numeral_system == 'hexadecimal':
        try:
            number = hex(int(number, 16))[2:]
        except ValueError:
            if error_handling == 'raise':
                raise ValueError("Invalid hexadecimal number.")
            elif error_handling == 'default':
                return default_value

    # Extract digits based on positions
    extracted_digits = []
    for pos in positions:
        try:
            # Convert 1-based index to 0-based
            index = pos - 1
            extracted_digits.append(number[index])
        except IndexError:
            if error_handling == 'raise':
                raise IndexError(f"Position {pos} is out of range.")
            elif error_handling == 'default':
                extracted_digits.append(default_value)
            # 'ignore' does nothing

    return ''.join(extracted_digits)

