def concatenate_values(values, separator='', output_format='string', trim_whitespace=False, case_conversion='none'):
    # Validate input
    if not isinstance(values, list) or len(values) < 2:
        return {'error': 'Invalid input: At least two values are required for concatenation.'}

    # Process values
    processed_values = []
    for value in values:
        if value is None:
            continue
        if isinstance(value, (int, float)):
            value = str(value)
        elif not isinstance(value, str):
            return {'error': 'Invalid input: Values must be strings, numbers, or null.'}

        if trim_whitespace:
            value = value.strip()

        if case_conversion == 'uppercase':
            value = value.upper()
        elif case_conversion == 'lowercase':
            value = value.lower()

        processed_values.append(value)

    # Concatenate values
    result = separator.join(processed_values)

    # Convert output format if necessary
    if output_format == 'number':
        try:
            result = float(result) if '.' in result else int(result)
        except ValueError:
            return {'error': 'Invalid conversion to number format.'}

    return {'result': result}

