    # Validate input parameters
    if not isinstance(names, list) or len(names) == 0:
        return {'error': 'Invalid input: names must be a non-empty list of strings.'}
    if not all(isinstance(name, str) for name in names):
        return {'error': 'Invalid input: all items in names must be strings.'}
    if not isinstance(include_special_characters, bool):
        return {'error': 'Invalid input: include_special_characters must be a boolean.'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'Invalid input: case_sensitive must be a boolean.'}
    if not isinstance(character_types, list) or not all(ct in ['letters', 'digits', 'special'] for ct in character_types):
        return {'error': 'Invalid input: character_types must be a list containing any of ["letters", "digits", "special"].'}
    if output_format not in ['integer', 'text', 'detailed']:
        return {'error': 'Invalid input: output_format must be one of ["integer", "text", "detailed"].'}

    # Initialize count
    total_count = 0
    detailed_count = {'letters': 0, 'digits': 0, 'special': 0}

    # Define character sets
    import string
    letter_set = string.ascii_letters if case_sensitive else string.ascii_lowercase
    digit_set = string.digits
    special_set = string.punctuation

    # Process each name
    for name in names:
        for char in name:
            if 'letters' in character_types and char.lower() in letter_set:
                detailed_count['letters'] += 1
            elif 'digits' in character_types and char in digit_set:
                detailed_count['digits'] += 1
            elif 'special' in character_types and char in special_set:
                detailed_count['special'] += 1

    # Calculate total count based on character types
    total_count = sum(detailed_count[ct] for ct in character_types)

    # Return result based on output format
    if output_format == 'integer':
        return total_count
    elif output_format == 'text':
        return f'Total count: {total_count}'
    elif output_format == 'detailed':
