def advanced_arithmetic(operation: str, operands: list, precision: int = 2, format: str = 'decimal') -> str:
    # Validate operation
    if operation not in ['add', 'subtract', 'multiply', 'divide', 'modulus', 'exponentiate']:
        return 'Error: Invalid operation.'
    # Validate operands
    if len(operands) < 2:
        return 'Error: At least two operands are required.'
    # Perform the operation
    try:
        if operation == 'add':
            result = sum(operands)
        elif operation == 'subtract':
            result = operands[0] - sum(operands[1:])
        elif operation == 'multiply':
            result = 1
            for num in operands:
                result *= num
        elif operation == 'divide':
            result = operands[0]
            for num in operands[1:]:
                if num == 0:
                    return 'Error: Division by zero.'
                result /= num
        elif operation == 'modulus':
            result = operands[0]
            for num in operands[1:]:
                result %= num
        elif operation == 'exponentiate':
            result = operands[0]
            for num in operands[1:]:
                result **= num
        # Format the result
        if format == 'scientific':
            result_str = f'{result:.{precision}e}'
        else:
            result_str = f'{result:.{precision}f}'
        return result_str
    except Exception as e:
        return f'Error: {str(e)}'

