def enhanced_combinations_counter(input_string, combination_length=2, case_sensitive=False, ignore_non_alpha=True, output_format='count'):
    from itertools import combinations
    import re

    # Error handling for input types
    if not isinstance(input_string, str):
        return {'error': 'input_string must be a string'}
    if not isinstance(combination_length, int) or combination_length < 1:
        return {'error': 'combination_length must be a positive integer'}
    if not isinstance(case_sensitive, bool):
        return {'error': 'case_sensitive must be a boolean'}
    if not isinstance(ignore_non_alpha, bool):
        return {'error': 'ignore_non_alpha must be a boolean'}
    if output_format not in ['count', 'list', 'detailed']:
        return {'error': "output_format must be 'count', 'list', or 'detailed'"}

    # Process the input string
    if ignore_non_alpha:
        input_string = re.sub(r'[^a-zA-Z]', '', input_string)
    if not case_sensitive:
        input_string = input_string.lower()

    # Generate combinations
    comb_set = set(''.join(comb) for comb in combinations(input_string, combination_length))

    # Return based on output_format
    if output_format == 'count':
        return len(comb_set)
    elif output_format == 'list':
        return list(comb_set)
    elif output_format == 'detailed':
        from collections import Counter
        comb_counter = Counter(''.join(comb) for comb in combinations(input_string, combination_length))
        return {'total': len(comb_set), 'details': comb_counter}

