def extract_first_letter(input: str, case_sensitive: bool = True, output_format: str = 'character', trim_whitespace: bool = False, error_handling: str = 'warn') -> str:
    """
    Extracts the first letter of a given string based on specified parameters.

    Parameters:
    - input (str): The string from which to extract the first letter.
    - case_sensitive (bool): Determines if the extraction should consider case sensitivity.
    - output_format (str): The format of the output ('character', 'ascii_code', 'unicode', 'hex').
    - trim_whitespace (bool): Specifies whether to trim leading whitespace before extraction.
    - error_handling (str): Defines the error handling strategy ('ignore', 'warn', 'strict').

    Returns:
    - str: The first letter in the specified format.
    """
    # Error handling for invalid input
    if not isinstance(input, str) or len(input) == 0:
        if error_handling == 'strict':
            raise ValueError("Input must be a non-empty string.")
        elif error_handling == 'warn':
            print("Warning: Input must be a non-empty string.")
            return ''
        elif error_handling == 'ignore':
            return ''

    # Trim leading whitespace if specified
    if trim_whitespace:
        input = input.lstrip()

    # Extract the first letter
    first_letter = input[0]

    # Handle case sensitivity
    if not case_sensitive:
        first_letter = first_letter.lower()

    # Format the output
    if output_format == 'character':
        return first_letter
    elif output_format == 'ascii_code':
        return str(ord(first_letter))
    elif output_format == 'unicode':
        return f'U+{ord(first_letter):04X}'
    elif output_format == 'hex':
        return hex(ord(first_letter))

    # Default return if no valid output_format is specified
    return first_letter

# Example usage
result = extract_first_letter('William')
print(result)  # Output: 'W'

def enhanced_ascii_converter(characters, ignore_non_ascii=False, output_format='list', encoding_type='ASCII', error_handling='log', batch_size=100):
    """
    Convert characters to their ASCII codes or other specified encodings.

    :param characters: List of characters to convert.
    :param ignore_non_ascii: Whether to ignore non-ASCII characters.
    :param output_format: Format of the output ('list', 'dictionary', 'json', 'csv').
    :param encoding_type: Encoding type ('ASCII', 'UTF-8', 'UTF-16').
    :param error_handling: Error handling strategy ('ignore', 'log', 'raise').
    :param batch_size: Number of characters to process in each batch.
    :return: Converted characters in the specified format.
    """
    import json
    import csv
    from io import StringIO

    if not isinstance(characters, list) or not all(isinstance(c, str) and len(c) == 1 for c in characters):
        raise ValueError("'characters' must be a list of single-character strings.")

    if output_format not in ['list', 'dictionary', 'json', 'csv']:
        raise ValueError("Invalid output format.")

    if encoding_type not in ['ASCII', 'UTF-8', 'UTF-16']:
        raise ValueError("Invalid encoding type.")

    if error_handling not in ['ignore', 'log', 'raise']:
        raise ValueError("Invalid error handling strategy.")

    if not (1 <= batch_size <= 1000):
        raise ValueError("'batch_size' must be between 1 and 1000.")

    ascii_codes = {}
    errors = []

    for char in characters:
        try:
            if encoding_type == 'ASCII':
                code = ord(char)
                if code > 127 and ignore_non_ascii:
                    continue
            else:
                code = char.encode(encoding_type)
            ascii_codes[char] = code
        except Exception as e:
            if error_handling == 'raise':
                raise e
            elif error_handling == 'log':
                errors.append((char, str(e)))

    if output_format == 'list':
        result = list(ascii_codes.values())
    elif output_format == 'dictionary':
        result = ascii_codes
    elif output_format == 'json':
        result = json.dumps(ascii_codes)
    elif output_format == 'csv':
        output = StringIO()
        writer = csv.writer(output)
        for char, code in ascii_codes.items():
            writer.writerow([char, code])
        result = output.getvalue()

    if errors and error_handling == 'log':
        print("Errors encountered:", errors)

    return result

# Example usage for the question:
# What is the ASCII code of W?
result = enhanced_ascii_converter(['W'], output_format='list')
print(result)  # Output: [87]
